import type { RtEncyclopediaEntry } from "./respiratory-therapy-encyclopedia-data";

export const RT_ENCYCLOPEDIA_BATCH5: RtEncyclopediaEntry[] = [

  {slug:"tracheostomy-care-management",title:"Tracheostomy Care & Management",category:"Airway Management",seoTitle:"Tracheostomy Care – Tube Types, Suctioning & Decannulation | RRT",seoDescription:"Master tracheostomy care: tube selection, cuff management, suctioning, speaking valves, and decannulation criteria for the RRT exam.",seoKeywords:["tracheostomy","trach care","cuff management","speaking valve","Passy-Muir","decannulation","RRT exam"],overview:"Tracheostomy management is a core respiratory therapy competency. It involves tube selection, stoma care, cuff management, suctioning, communication facilitation (speaking valves), and decannulation assessment. Tracheostomy provides a stable airway, reduces dead space, facilitates weaning, and allows oral intake compared to endotracheal intubation.",mechanismPhysiology:"Tracheostomy tube components: outer cannula (maintains stoma), inner cannula (removable for cleaning — prevents occlusion), obturator (used for insertion only), cuff (seals airway for PPV and aspiration prevention), 15 mm adapter (connects to ventilator/BVM). Tube types: cuffed (ventilated patients, aspiration risk), uncuffed (stable airway, weaning), fenestrated (speech facilitation — allows air through fenestration to vocal cords), double-lumen (has inner cannula), single-lumen (no inner cannula — must clean entire tube if occluded).",clinicalRelevance:"Early tracheostomy (within 7–10 days of intubation) vs late: systematic reviews suggest possible reductions in ICU stay and ventilator days. Indications: prolonged mechanical ventilation, upper airway obstruction, secretion management, airway protection. Cuff pressure monitoring: maintain 20–25 cmH2O (minimum to seal, prevents tracheal mucosal ischemia). Speaking valve (Passy-Muir valve): one-way inspiratory valve — patient inhales through trach but exhales through upper airway past vocal cords. REQUIRES: deflated cuff, patent upper airway, adequate cognitive function.",signsSymptoms:"Signs of tube problems: increased WOB, desaturation, inability to pass suction catheter (mucus plug or tube displacement), subcutaneous emphysema around stoma (false passage), air leak despite cuff inflation (cuff rupture or tube displacement), bleeding from stoma.",assessment:"Daily assessment: stoma site (redness, drainage, granulation tissue), tube position and security, cuff pressure (20–25 cmH2O), inner cannula patency, secretion volume/color/consistency. Before speaking valve placement: assess ability to tolerate cuff deflation, air leak around deflated cuff (confirms upper airway patency), SpO2 during trial. Decannulation readiness: stable airway, adequate cough strength, manageable secretions, no ventilator need, swallow assessment passed.",management:"Stoma care: clean q8h with half-strength H2O2, apply clean dressing, secure ties (one-finger space). Suctioning: sterile technique, pre-oxygenate, appropriate catheter size (no more than half the inner diameter of the tube), suction ≤ 10 seconds, limit passes. Inner cannula: clean q4–8h or as needed. Tube change: first change at 5–7 days post-operatively (by physician), subsequent changes q1–4 weeks. Emergency: accidental decannulation — if < 7 days old (immature tract), DO NOT reinsert blindly → oral intubation. If > 7 days (mature tract) → reinsert with obturator.",complications:"Accidental decannulation, mucus plug/obstruction, tracheal stenosis (cuff overinflation), tracheoinnominate artery fistula (massive hemorrhage — life-threatening), tracheoesophageal fistula, granulation tissue, infection, tracheomalacia.",clinicalPearls:["Cuff pressure should be maintained at 20–25 cmH2O — higher pressures cause tracheal mucosal ischemia and stenosis","Speaking valve (Passy-Muir) requires a DEFLATED CUFF — air must exit around the tube past vocal cords","For accidental decannulation < 7 days: DO NOT blindly reinsert — the tract is immature and false passage risk is high","Suction catheter size: outer diameter should not exceed half the inner diameter of the trach tube"],examPitfalls:["Placing a speaking valve with the cuff inflated — the patient cannot exhale and will suffocate","Using a suction catheter that is too large — occludes the airway during suctioning","Not maintaining cuff pressure at 20–25 cmH2O — both over- and under-inflation cause problems","Blindly reinserting a trach tube in a fresh (<7 day) stoma after accidental decannulation"],faqJson:[{question:"Why must the cuff be deflated for a speaking valve?",answer:"The Passy-Muir valve is a one-way valve — air enters through the trach tube during inspiration but the valve closes during expiration. Air must exit around the tube, past the vocal cords, and out through the mouth/nose. If the cuff is inflated, air cannot escape, causing air trapping and potentially fatal barotrauma."},{question:"What is a tracheoinnominate artery fistula?",answer:"A rare but life-threatening complication where the trach tube erodes into the innominate (brachiocephalic) artery. Presents as massive pulsatile bleeding from the stoma. Emergency management: hyperinflate cuff (tamponade), apply digital pressure through stoma against sternum, emergent surgery."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"difficult-airway-management",title:"Difficult Airway Management",category:"Airway Management",seoTitle:"Difficult Airway – Assessment, Planning & Rescue Devices | RRT",seoDescription:"Learn difficult airway management: LEMON assessment, ASA algorithm, supraglottic airways, cricothyrotomy, and video laryngoscopy for the RRT exam.",seoKeywords:["difficult airway","LEMON","Mallampati","supraglottic airway","LMA","cricothyrotomy","video laryngoscopy","RRT exam"],overview:"Difficult airway management is the systematic approach to anticipating, preparing for, and managing airways that are challenging to intubate or ventilate. The ASA Difficult Airway Algorithm guides decision-making. Assessment tools include LEMON (Look, Evaluate 3-3-2, Mallampati, Obstruction, Neck mobility) and Mallampati classification. Rescue devices include supraglottic airways (LMA), video laryngoscopy, bougie, and surgical cricothyrotomy as the final rescue.",mechanismPhysiology:"Difficult intubation occurs when conventional direct laryngoscopy fails to provide adequate glottic visualization. Causes: limited mouth opening (TMJ disease, infection), large tongue (Mallampati III-IV), limited neck extension (cervical spine disease/immobilization), anterior larynx (short thyromental distance), obesity, facial trauma, airway edema, anatomic variants. Difficult mask ventilation: obesity, beard, edentulous, elderly, OSA, short neck. The 'cannot intubate, cannot oxygenate' (CICO) scenario is the most feared — requires immediate surgical airway.",clinicalRelevance:"LEMON assessment: Look externally (facial trauma, obesity, short neck), Evaluate 3-3-2 rule (3 fingers mouth opening, 3 fingers hyoid-to-chin, 2 fingers thyroid-to-hyoid), Mallampati score (I-IV — higher = more difficult), Obstruction (tumors, epiglottitis, abscess), Neck mobility (c-spine immobilization limits extension). Mallampati I: full visibility of tonsils, uvula, soft palate. Mallampati IV: only hard palate visible. Video laryngoscopy improves first-attempt success by 25–30% compared to direct laryngoscopy.",signsSymptoms:"Predictors of difficult intubation: Mallampati III-IV, mouth opening < 3 cm, thyromental distance < 6 cm, limited neck extension, short thick neck, obesity (BMI > 35), facial hair (difficult mask seal), history of head/neck radiation, OSA, previous difficult intubation.",assessment:"Pre-intubation assessment: LEMON evaluation, review previous anesthetic/intubation records, assess for potential difficult mask ventilation (MOANS: Mask seal, Obesity, Age > 55, No teeth, Stiff lungs). Have a plan and backup plan before every intubation attempt. Equipment check: standard and backup equipment at bedside.",management:"ASA Algorithm key points: (1) Always consider awake intubation if difficult airway predicted. (2) After failed intubation: call for help, attempt supraglottic airway (LMA/i-gel), limit intubation attempts to 3 + 1 expert attempt. (3) CICO: immediate front-of-neck access (cricothyrotomy). Equipment: video laryngoscope, bougie/stylet, supraglottic airways (LMA, i-gel), fiberoptic bronchoscope for awake intubation, cricothyrotomy kit. RT role: prepare all equipment, assist with positioning (ramping obese patients), provide bag-mask ventilation between attempts, monitor SpO2.",complications:"Esophageal intubation, aspiration, airway trauma, dental injury, hypoxic brain injury from prolonged attempts, cannot-intubate-cannot-oxygenate leading to cardiac arrest, surgical airway complications.",clinicalPearls:["ALWAYS have a backup plan — the most dangerous airway is the one you didn't anticipate being difficult","Limit intubation attempts — each attempt causes edema and bleeding that makes the next attempt harder","Video laryngoscopy should be the default in predicted difficult airways — improves glottic visualization","In CICO: do NOT keep attempting intubation — perform cricothyrotomy immediately"],examPitfalls:["Not performing a pre-intubation airway assessment","Making repeated intubation attempts without a backup plan","Not knowing the LEMON assessment components","Delaying surgical airway in a CICO scenario"],faqJson:[{question:"What is the LEMON airway assessment?",answer:"L: Look externally (facial trauma, obesity). E: Evaluate 3-3-2 rule (mouth opening, hyoid-chin distance, thyroid-hyoid distance). M: Mallampati score (I–IV). O: Obstruction (tumors, infections). N: Neck mobility (cervical spine limitations). Any abnormality increases likelihood of difficult intubation."},{question:"What is a CICO scenario?",answer:"Cannot Intubate, Cannot Oxygenate — the most critical airway emergency. The patient cannot be intubated AND cannot be adequately oxygenated by bag-mask or supraglottic airway. Requires immediate surgical airway (cricothyrotomy) as a life-saving intervention."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"pulmonary-embolism-respiratory",title:"Pulmonary Embolism for Respiratory Therapists",category:"Critical Care",seoTitle:"Pulmonary Embolism – Respiratory Assessment & Management | RRT",seoDescription:"Learn pulmonary embolism: pathophysiology, V/Q mismatch, diagnosis, ABG findings, and respiratory management for the RRT exam.",seoKeywords:["pulmonary embolism","PE","V/Q mismatch","D-dimer","CT angiography","Wells score","RRT exam"],overview:"Pulmonary embolism (PE) is acute obstruction of pulmonary arterial vasculature, most commonly by thrombus from deep venous thrombosis (DVT). PE causes V/Q mismatch (ventilated but unperfused lung = dead space), acute right ventricular failure, and potentially cardiovascular collapse. PE is the third most common cause of cardiovascular death and a key exam topic for respiratory therapists.",mechanismPhysiology:"Thrombus from DVT (usually lower extremity) dislodges and travels through the right heart to the pulmonary arteries. Obstruction creates: (1) increased dead space (ventilated but not perfused alveoli), (2) V/Q mismatch in surrounding lung, (3) increased PVR → RV strain → RV dilation → decreased LV filling → decreased CO. (4) Hypoxemia from V/Q mismatch, shunting, and low mixed venous O2 (low CO). (5) Hyperventilation (reflex tachypnea) → respiratory alkalosis. Large PE: acute cor pulmonale, obstructive shock, cardiac arrest (PEA).",clinicalRelevance:"Classic ABG: hypoxemia + respiratory alkalosis (acute hyperventilation) + elevated A-a gradient. However, 15–20% of PE patients have NORMAL PaO2. Other findings: elevated D-dimer (sensitive but not specific), ECG (sinus tachycardia most common, S1Q3T3 classic but uncommon), CXR (often normal — Westermark sign, Hampton hump are rare). CT pulmonary angiography (CTPA) is the gold standard for diagnosis.",signsSymptoms:"Sudden-onset dyspnea (most common symptom), pleuritic chest pain, tachypnea, tachycardia, hemoptysis, syncope (massive PE), unilateral leg swelling (DVT). Massive PE: hypotension, shock, cardiac arrest. Risk factors (Virchow's triad): stasis (immobility, long travel), endothelial injury (surgery, trauma), hypercoagulability (cancer, pregnancy, oral contraceptives, inherited thrombophilia).",assessment:"Clinical probability: Wells score or Geneva score. D-dimer: if low probability and D-dimer negative → PE effectively ruled out. CTPA: definitive diagnosis. ABG: hypoxemia with elevated A-a gradient and respiratory alkalosis (typical but not always present). Echocardiography: RV dilation, McConnell's sign (acute PE). Point-of-care ultrasound: assess RV function, look for DVT.",management:"Oxygen therapy for hypoxemia (target SpO2 > 90%). Anticoagulation: heparin (UFH or LMWH) for most PE. Massive PE (hemodynamic instability): systemic thrombolysis (tPA), catheter-directed therapy, or surgical embolectomy. Submassive PE (RV strain without hypotension): anticoagulation + close monitoring, consider thrombolysis if deterioration. Mechanical ventilation if needed: avoid high PEEP (worsens RV failure), maintain preload (IV fluids cautiously), avoid hypoxia/hypercapnia/acidosis (increase PVR).",complications:"Cardiovascular collapse, cardiac arrest (PEA), chronic thromboembolic PH (CTEPH), post-PE syndrome, recurrent PE, bleeding from anticoagulation/thrombolysis.",clinicalPearls:["Classic PE ABG: hypoxemia + respiratory alkalosis + elevated A-a gradient — but 15–20% have normal PaO2","D-dimer is sensitive but NOT specific — a negative D-dimer effectively rules out PE in low-probability patients","If intubating a massive PE patient: be prepared for cardiovascular collapse (positive pressure worsens RV failure)","Sinus tachycardia is the most common ECG finding in PE, NOT S1Q3T3"],examPitfalls:["Ruling out PE based on a normal PaO2 — 15–20% of PE patients have normal O2","Not knowing that D-dimer is sensitive but not specific (elevated in many conditions)","Applying high PEEP to a PE patient — increases RV afterload and may cause hemodynamic collapse","Thinking S1Q3T3 is the most common ECG finding — sinus tachycardia is most common"],faqJson:[{question:"Why does PE cause respiratory alkalosis?",answer:"PE causes reflex tachypnea and hyperventilation through: stimulation of juxtacapillary (J) receptors in the lung, hypoxemia-driven chemoreceptor stimulation, and anxiety/pain. The increased minute ventilation blows off CO2 faster than it is produced, causing respiratory alkalosis."},{question:"Why is high PEEP dangerous in massive PE?",answer:"Massive PE causes RV failure from increased PVR. PEEP further increases intrathoracic pressure and PVR, worsening RV afterload. The dilated RV is also preload-dependent — PEEP reduces venous return. This combination can cause cardiovascular collapse."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ventilator-associated-pneumonia",title:"Ventilator-Associated Pneumonia (VAP)",category:"Infection Control",seoTitle:"VAP – Ventilator-Associated Pneumonia Prevention & Management | RRT",seoDescription:"Learn VAP: risk factors, VAP bundle, prevention strategies, diagnosis, and the respiratory therapist's role for the RRT exam.",seoKeywords:["VAP","ventilator-associated pneumonia","VAP bundle","oral care","subglottic suctioning","HOB elevation","RRT exam"],overview:"Ventilator-associated pneumonia (VAP) is pneumonia developing ≥ 48 hours after endotracheal intubation. It is the most common healthcare-associated infection in ICU patients, occurring in 10–25% of ventilated patients. VAP increases ICU stay by 5–7 days, adds significant cost, and has attributable mortality of 13%. The VAP prevention bundle is a core RT responsibility.",mechanismPhysiology:"Pathogenesis: microaspiration of contaminated oropharyngeal secretions past the ET tube cuff into the lower respiratory tract. Biofilm formation on the ET tube provides a bacterial reservoir. Risk factors: duration of mechanical ventilation (risk increases 1–3% per day), supine positioning, inadequate oral care, subglottic secretion pooling above the cuff, circuit contamination, impaired immune function, use of acid-suppressive medications (increase gastric colonization).",clinicalRelevance:"VAP prevention bundle (evidence-based — RT role is critical): (1) Elevate HOB 30–45° (reduces aspiration risk). (2) Oral care with chlorhexidine q6h (controversial — some recent evidence questions benefit). (3) Subglottic suctioning (ET tubes with subglottic suction port). (4) Daily sedation vacation and spontaneous breathing trial assessment. (5) Peptic ulcer prophylaxis. (6) DVT prophylaxis. (7) Maintain cuff pressure 20–25 cmH2O. RT-specific: avoid unnecessary circuit changes (only change if visibly contaminated), drain condensation from circuits away from patient, keep ventilator circuits closed.",signsSymptoms:"New or progressive infiltrate on CXR + at least 2 of: temperature > 38°C or < 36°C, WBC > 12,000 or < 4,000, purulent secretions. Clinical Pulmonary Infection Score (CPIS) > 6 suggests VAP. Late-onset VAP (≥ 5 days): higher risk of MDR organisms (MRSA, Pseudomonas, Acinetobacter).",assessment:"Clinical assessment: new fever, increasing secretions (change in color/volume/consistency), worsening oxygenation, new infiltrate on CXR. Microbiologic: tracheal aspirate culture (sensitive but not specific), bronchoscopic BAL (more specific, ≥ 10^4 CFU/mL diagnostic), protected specimen brush (≥ 10^3 CFU/mL). Blood cultures. Monitor for clinical improvement within 48–72 hours of antibiotic initiation.",management:"Prevention (RT-driven bundle): HOB elevation, oral care, cuff pressure maintenance, subglottic suctioning, hand hygiene, circuit management, sedation/SBT protocol, early mobilization. Treatment: empiric broad-spectrum antibiotics (cover Pseudomonas, MRSA for late-onset), de-escalate based on culture results, 7-day antibiotic course (shorter courses equally effective). Non-pharmacological: early extubation when possible — the best VAP prevention is removing the ET tube.",complications:"Treatment failure, MDR organism selection, Clostridioides difficile colitis from antibiotics, longer ICU stay, increased mortality.",clinicalPearls:["The BEST VAP prevention is early extubation — every extra ventilator day increases VAP risk","Maintain ET tube cuff pressure at 20–25 cmH2O — prevents microaspiration of subglottic secretions","Do NOT change the ventilator circuit routinely — only change if visibly contaminated","Drain circuit condensation AWAY from the patient — it is contaminated"],examPitfalls:["Routinely changing ventilator circuits — this actually INCREASES VAP risk","Not maintaining HOB elevation at 30–45° — a simple but critical prevention measure","Forgetting to monitor cuff pressure — it is a key VAP prevention element","Not knowing the components of the VAP prevention bundle"],faqJson:[{question:"What is the VAP prevention bundle?",answer:"A set of evidence-based interventions applied together: HOB elevation 30–45°, oral care, sedation vacation/SBT, DVT and peptic ulcer prophylaxis, cuff pressure maintenance, subglottic suctioning (when available), and closed suction systems. The RT plays a central role in implementing most of these."},{question:"Why should ventilator circuits NOT be changed routinely?",answer:"Studies show that routine circuit changes increase VAP risk by introducing contamination during the change process. Circuits should only be changed when visibly contaminated or malfunctioning. Circuit condensation should be drained regularly away from the patient."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"bronchodilator-response-testing",title:"Bronchodilator Response Testing",category:"Pulmonary Function Testing",seoTitle:"Bronchodilator Response – Pre/Post Spirometry Interpretation | RRT",seoDescription:"Learn bronchodilator response testing: criteria, interpretation, asthma vs COPD differentiation, and clinical significance for the RRT exam.",seoKeywords:["bronchodilator response","reversibility testing","pre-post spirometry","FEV1 reversibility","asthma diagnosis","RRT exam"],overview:"Bronchodilator response (BDR) testing evaluates airflow reversibility by comparing spirometry before and after administration of a short-acting bronchodilator (typically albuterol 400 mcg via MDI with spacer). A positive BDR supports the diagnosis of asthma and helps differentiate it from COPD. However, response can overlap between diseases, and a negative BDR does not exclude asthma.",mechanismPhysiology:"Bronchodilator reversal of airflow obstruction occurs through relaxation of airway smooth muscle, which is the dominant mechanism in asthma (bronchospasm is a key feature). In COPD, structural changes (fibrosis, mucus gland hypertrophy, loss of elastic recoil) cause fixed obstruction that does not fully reverse with bronchodilators. Testing protocol: baseline spirometry → administer albuterol 400 mcg via MDI+spacer (or nebulized 2.5 mg) → wait 15–20 minutes → repeat spirometry. Patient preparation: withhold SABA for 4–6 hours, LABA for 12–24 hours before testing.",clinicalRelevance:"ATS/ERS criteria for positive BDR: increase in FEV1 or FVC of ≥ 200 mL AND ≥ 12% from baseline. Some guidelines use ≥ 10% of predicted FEV1 as an alternative. A positive BDR is SUGGESTIVE of asthma but not diagnostic alone. A negative BDR does NOT rule out asthma (airway remodeling, suboptimal bronchodilator delivery, or low baseline obstruction). COPD patients can show partial reversibility. Use BDR in context: clinical history, symptoms, and other tests (methacholine challenge, FeNO).",signsSymptoms:"Reasons for testing: suspected asthma (episodic wheeze, cough, dyspnea), airflow obstruction on spirometry (to assess reversibility), differentiating asthma from COPD, monitoring treatment response, pre-operative assessment.",assessment:"Calculate: absolute change (post FEV1 − pre FEV1) and percent change [(post − pre)/pre × 100]. Positive BDR: ≥ 200 mL AND ≥ 12% improvement in FEV1 or FVC. Document: pre and post FEV1, FVC, FEV1/FVC, absolute and percent change, bronchodilator used, dose, and delivery method. Assess quality of spirometry efforts (ATS acceptability and repeatability criteria must be met for both pre and post).",management:"Positive BDR: supports asthma diagnosis — initiate ICS-based therapy. Negative BDR with clinical suspicion of asthma: consider methacholine challenge test (assesses airway hyperresponsiveness), repeat testing at another visit, or therapeutic trial of ICS. In COPD: BDR does not predict long-term bronchodilator benefit — prescribe bronchodilators regardless of BDR result (GOLD guidelines). Documentation: include in PFT interpretation report.",complications:"False negative: patient did not withhold bronchodilators, inadequate dose/technique, minimal baseline obstruction. False positive: physiologic variability, learning effect between pre and post spirometry. Bronchospasm from forced maneuvers (rare).",clinicalPearls:["Both criteria must be met for positive BDR: ≥ 200 mL AND ≥ 12% improvement in FEV1 or FVC","A negative BDR does NOT rule out asthma — consider methacholine challenge if clinical suspicion remains","In COPD, prescribe bronchodilators regardless of BDR — the acute test does not predict chronic benefit","Withhold SABA 4–6 hours and LABA 12–24 hours before testing for accurate results"],examPitfalls:["Requiring only 12% change without 200 mL (or vice versa) — BOTH criteria must be met","Diagnosing asthma based solely on a positive BDR — it is suggestive but not diagnostic alone","Withholding bronchodilators from COPD patients because of a negative BDR","Not ensuring proper medication withholding before testing"],faqJson:[{question:"What are the ATS/ERS criteria for a positive bronchodilator response?",answer:"Improvement in FEV1 or FVC of ≥ 200 mL AND ≥ 12% from baseline. Both the absolute and percentage criteria must be met simultaneously. The standard bronchodilator is albuterol 400 mcg via MDI with spacer, measured 15–20 minutes after administration."},{question:"Can COPD patients show bronchodilator reversibility?",answer:"Yes — some COPD patients show partial reversibility, especially those with an eosinophilic or asthmatic component. However, BDR in COPD does not predict long-term bronchodilator benefit. GOLD guidelines recommend prescribing bronchodilators for COPD regardless of BDR result."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"neuromuscular-blocking-agents",title:"Neuromuscular Blocking Agents in Respiratory Care",category:"Pharmacology",seoTitle:"Neuromuscular Blockers – Paralysis for Ventilation & ARDS | RRT",seoDescription:"Learn neuromuscular blocking agents: succinylcholine, rocuronium, train-of-four monitoring, ARDS indications, and RT considerations for the RRT exam.",seoKeywords:["neuromuscular blockade","NMB","succinylcholine","rocuronium","train of four","paralysis","ARDS","RRT exam"],overview:"Neuromuscular blocking agents (NMBAs) are used in respiratory care for intubation facilitation (rapid sequence intubation), refractory ARDS with dyssynchrony, and to reduce oxygen consumption in severe respiratory failure. NMBAs paralyze skeletal muscles by blocking neuromuscular junction transmission but have NO sedative, analgesic, or anxiolytic properties — patients MUST receive concurrent sedation and analgesia.",mechanismPhysiology:"Depolarizing agents (succinylcholine): bind ACh receptors, causing initial fasciculation then sustained depolarization → flaccid paralysis. Rapid onset (30–60 seconds), short duration (5–10 minutes). Metabolized by pseudocholinesterase. Non-depolarizing agents (rocuronium, vecuronium, cisatracurium): competitive antagonists at ACh receptors — prevent ACh from binding. Onset 1–3 minutes, duration 30–90 minutes. Cisatracurium undergoes Hofmann elimination (organ-independent) — preferred in hepatic/renal failure.",clinicalRelevance:"RSI: succinylcholine (1–1.5 mg/kg) or rocuronium (1.2 mg/kg) for fastest paralysis onset. ACURASYS trial: early cisatracurium infusion for 48 hours in severe ARDS (P/F < 150) improved 90-day mortality (later ROSE trial showed no benefit with lighter sedation — current practice: NMB for refractory dyssynchrony, not routinely). Train-of-four (TOF) monitoring: peripheral nerve stimulator at ulnar nerve — count visible twitches (0–4). Target: 1–2/4 twitches for adequate paralysis. 0/4 = complete blockade (excessive). 4/4 with fade = partial blockade.",signsSymptoms:"Indications: intubation facilitation (RSI), refractory patient-ventilator dyssynchrony in severe ARDS despite deep sedation, severe refractory hypoxemia, reduced O2 consumption in shock, controlled hypothermia protocols, status epilepticus (seizure ablation). Contraindications to succinylcholine: hyperkalemia, burn injury > 48h, spinal cord injury, neuromuscular disease, malignant hyperthermia risk.",assessment:"TOF monitoring: apply peripheral nerve stimulator, deliver 4 stimuli, count visible twitches. Target 1–2/4. If 0/4: hold infusion until twitches return. Daily sedation holiday is NOT possible with continuous NMB — sedate deeply and monitor with BIS (bispectral index) if available. Assess for complications: pressure injuries (immobile patient), corneal exposure (cannot blink — eye care essential), DVT/PE risk.",management:"RSI: succinylcholine 1–1.5 mg/kg IV (fastest onset) or rocuronium 1.2 mg/kg IV. Reversal: sugammadex reverses rocuronium immediately. Continuous infusion: cisatracurium preferred in ICU (organ-independent metabolism). ALWAYS ensure adequate sedation and analgesia BEFORE and DURING paralysis. Monitor TOF q4–6h. Provide: eye care (lubricant, tape lids), DVT prophylaxis, pressure injury prevention (turn q2h), reassurance (assume patient can hear).",complications:"Awareness during paralysis (if inadequate sedation — terrifying for patient), prolonged weakness/ICU-acquired weakness, pressure injuries, corneal ulceration, DVT/PE, hyperkalemia (succinylcholine), malignant hyperthermia (succinylcholine), anaphylaxis.",clinicalPearls:["NMBAs have NO sedative or analgesic properties — ALWAYS ensure deep sedation before and during paralysis","Train-of-four target: 1–2/4 twitches — 0/4 means excessive paralysis, hold infusion","Cisatracurium is preferred in ICU — organ-independent Hofmann elimination","Sugammadex can immediately reverse rocuronium — important for failed intubation scenarios"],examPitfalls:["Giving NMBAs without ensuring adequate sedation — the patient is aware but paralyzed","Not monitoring TOF during continuous NMB infusion","Using succinylcholine in patients with hyperkalemia, burns > 48h, or spinal cord injury","Thinking NMBAs provide sedation or pain relief — they do NEITHER"],faqJson:[{question:"Why must sedation be given with NMBAs?",answer:"NMBAs block skeletal muscle contraction but have no effect on consciousness, pain perception, or anxiety. Without adequate sedation and analgesia, the patient is fully awake, aware, and in pain but completely unable to move or communicate — a traumatic experience."},{question:"What is train-of-four monitoring?",answer:"A peripheral nerve stimulator delivers 4 electrical impulses to the ulnar nerve. The number of visible thumb twitches indicates the degree of neuromuscular blockade: 4/4 = no/minimal blockade, 1–2/4 = adequate blockade (clinical target), 0/4 = excessive blockade (hold infusion until twitches return)."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"metered-dose-inhaler-technique",title:"Metered-Dose Inhaler (MDI) Technique",category:"Pharmacology",seoTitle:"MDI Technique – Proper Use, Spacers & Common Errors | RRT",seoDescription:"Master MDI technique: step-by-step use, spacer benefits, common errors, and patient education for the RRT exam.",seoKeywords:["MDI","metered dose inhaler","inhaler technique","spacer","valved holding chamber","aerosol therapy","RRT exam"],overview:"Proper metered-dose inhaler (MDI) technique is critical for effective drug delivery. Studies show 50–80% of patients use MDIs incorrectly, reducing drug deposition to as low as 10% of the emitted dose. The respiratory therapist is the primary educator for inhaler technique. Using a spacer/valved holding chamber (VHC) significantly improves drug delivery and reduces oropharyngeal side effects.",mechanismPhysiology:"MDI components: pressurized canister containing drug + propellant (HFA), metering valve (delivers consistent dose), actuator (mouthpiece). Upon actuation, propellant rapidly expands, creating a high-velocity aerosol plume (initially > 30 m/s). Without proper technique, most drug impacts the oropharynx. Spacer/VHC function: (1) slows the aerosol plume (reduces oropharyngeal impaction), (2) allows large particles to fall out (rain out), (3) eliminates need for hand-breath coordination (VHC holds the aerosol for 3–5 seconds), (4) reduces oropharyngeal candidiasis with ICS.",clinicalRelevance:"Proper technique steps: (1) Shake the MDI 15–20 times. (2) Prime if new or unused for >2 weeks (4 actuations into air). (3) Exhale to FRC (not to RV — don't strain). (4) Place mouthpiece between teeth, seal lips. (5) Begin slow deep inspiration. (6) Actuate at the beginning of inspiration. (7) Continue slow deep breath over 3–5 seconds. (8) Hold breath for 10 seconds (or as long as comfortable). (9) If second puff: wait 30–60 seconds. (10) Rinse mouth if using ICS. With spacer: actuate into spacer, then inhale slowly within 5 seconds (or use tidal breathing for 4–6 breaths in children).",signsSymptoms:"Signs of poor technique: drug taste in mouth (oropharyngeal deposition), lack of symptom improvement despite adherence, oral candidiasis with ICS (inadequate mouth rinsing, no spacer), hoarseness (ICS without spacer). Common errors: actuating before inhalation (poor coordination), inhaling too fast (impaction), not shaking MDI, not holding breath, not priming.",assessment:"Assess technique at EVERY visit (teach-back method): ask the patient to demonstrate their inhaler technique. Check: shaking, priming (if needed), exhalation before use, slow deep inhalation, coordination of actuation and inspiration, breath hold, mouth rinsing (ICS). Document technique assessment and education provided.",management:"Education: demonstrate correct technique, observe patient perform it (teach-back), correct errors, reassess at next visit. Spacer/VHC: recommend for ALL ICS users (reduces oropharyngeal candidiasis and dysphonia), ALL patients with poor hand-breath coordination, children, elderly. Spacer care: wash with dilute detergent monthly, air dry (do not towel dry — creates static charge that attracts drug particles). Replace spacer every 6–12 months.",complications:"Inadequate drug delivery (most common consequence of poor technique), oropharyngeal candidiasis (ICS without spacer/rinsing), dysphonia (ICS), paradoxical bronchospasm (rare), spacer static charge reducing drug delivery.",clinicalPearls:["50–80% of patients use MDIs incorrectly — assess technique at EVERY visit","A spacer reduces oropharyngeal ICS deposition from ~80% to ~20% — recommend for ALL ICS users","Slow deep inhalation over 3–5 seconds is critical — fast inhalation causes oropharyngeal impaction","Do NOT towel-dry spacers — this creates static charge that attracts drug particles; air-dry only"],examPitfalls:["Not assessing inhaler technique when a patient reports poor symptom control","Recommending fast, deep inhalation with MDI (correct: SLOW deep inhalation)","Not recommending a spacer with ICS — increases oropharyngeal side effects","Forgetting that MDIs need shaking before use (suspension formulations)"],faqJson:[{question:"Why is slow inhalation important with MDIs?",answer:"Slow inhalation (over 3–5 seconds) reduces the velocity of aerosol particles in the airway, decreasing impaction in the oropharynx and upper airways. Fast inhalation causes particles to impact in the throat rather than penetrating to the lower airways where they are needed."},{question:"Why is a spacer recommended with ICS?",answer:"Without a spacer, approximately 80% of ICS deposits in the oropharynx, causing local side effects (candidiasis, hoarseness) without therapeutic benefit. A spacer slows the aerosol, allows large particles to fall out, and eliminates the need for precise hand-breath coordination, increasing lung deposition."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ards-ecmo",title:"ECMO in ARDS",category:"ARDS",seoTitle:"ECMO for ARDS – Indications, Types & Respiratory Management | RRT",seoDescription:"Learn ECMO for ARDS: venovenous vs venoarterial, indications, lung rest ventilation, and RT role for the RRT exam.",seoKeywords:["ECMO","extracorporeal membrane oxygenation","VV ECMO","VA ECMO","ARDS","refractory hypoxemia","RRT exam"],overview:"Extracorporeal membrane oxygenation (ECMO) provides gas exchange support outside the body for patients with severe refractory ARDS. Venovenous (VV) ECMO is used for isolated respiratory failure, providing oxygenation and CO2 removal while allowing ultra-protective lung ventilation ('lung rest'). The EOLIA trial showed a trend toward mortality benefit. ECMO is a bridge to recovery, not a definitive treatment.",mechanismPhysiology:"VV ECMO: blood is drained from a large vein (IJ or femoral), passed through an oxygenator (membrane lung) where O2 is added and CO2 removed, then returned to the venous system near the right atrium. The native lungs still receive blood flow but can be ventilated with minimal settings ('rest settings'). Venoarterial (VA) ECMO: provides both cardiac AND respiratory support — blood returns to the arterial system, bypassing both lungs and heart. VA ECMO is used for combined cardiorespiratory failure. Oxygenator: microporous membrane where gas exchange occurs (sweep gas flow controls CO2 removal, FdO2 and blood flow rate control oxygenation).",clinicalRelevance:"VV ECMO indications (ARDS): P/F < 80 for > 6 hours despite optimal ventilation, P/F < 50 for > 3 hours, pH < 7.25 with PaCO2 > 60 for > 6 hours. CESAR trial and EOLIA trial support referral to ECMO centers for severe ARDS. Contraindications: irreversible underlying condition, severe comorbidities, prolonged high-pressure ventilation (> 7–10 days). RT role on ECMO: manage ventilator settings (rest settings), monitor circuit, troubleshoot alarms, manage sweep gas and FdO2.",signsSymptoms:"Candidates: severe ARDS failing conventional therapy (lung-protective ventilation, prone positioning, neuromuscular blockade), young age, reversible lung pathology (viral pneumonia, aspiration), minimal comorbidities. Signs ECMO is working: improved oxygenation, ability to reduce ventilator settings, hemodynamic improvement (if VA ECMO).",assessment:"Pre-ECMO: document severity (Murray lung injury score, P/F ratio, OI), assess candidacy (reversibility, comorbidities, goals of care). On ECMO: monitor circuit flows (typically 3–5 L/min), pre-oxygenator and post-oxygenator blood gases, sweep gas flow (controls CO2), FdO2 (controls oxygenation), native lung ventilator parameters (rest settings). Patient ABG monitoring from native circulation.",management:"Lung rest ventilation: low Vt (≤ 4 mL/kg IBW), low plateau pressure (< 25 cmH2O), low RR (10), FiO2 0.30, PEEP 10. This minimizes VILI while ECMO handles gas exchange. ECMO adjustments: increase sweep gas to increase CO2 removal, increase blood flow or FdO2 to increase oxygenation. Weaning: trial off ECMO by reducing sweep gas to 0 and FdO2 to 0.21 — if patient maintains acceptable ABG on moderate vent settings, decannulate.",complications:"Bleeding (anticoagulation — most common), thrombosis, hemolysis, circuit failure, infection (cannula site), air embolism, limb ischemia (VA ECMO), harlequin syndrome (differential hypoxia — VA ECMO), pump failure.",clinicalPearls:["VV ECMO provides respiratory support ONLY — if cardiac failure is present, VA ECMO is needed","Sweep gas flow controls CO2 removal on ECMO — analogous to minute ventilation on a ventilator","Lung rest settings minimize VILI: Vt ≤ 4 mL/kg, Pplat < 25, RR 10, FiO2 0.30, PEEP 10","ECMO is a BRIDGE to recovery — the underlying disease must be reversible"],examPitfalls:["Confusing VV ECMO (respiratory support) with VA ECMO (cardiorespiratory support)","Not knowing that sweep gas controls CO2 and blood flow/FdO2 controls oxygenation","Maintaining high ventilator settings on ECMO — the point is to REST the lungs","Not understanding ECMO as a bridge — it does not treat the underlying disease"],faqJson:[{question:"What is the difference between VV and VA ECMO?",answer:"VV (venovenous): blood is drained from and returned to the venous system — provides gas exchange support only. The patient's native heart must function adequately. VA (venoarterial): blood is drained from the venous system and returned to the arterial system — provides both cardiac and respiratory support."},{question:"How is CO2 removal controlled on ECMO?",answer:"Sweep gas flow rate (analogous to minute ventilation): increasing sweep gas flow removes more CO2 from the blood as it passes through the membrane oxygenator. Blood flow rate and FdO2 (fraction of delivered O2 to the oxygenator) control oxygenation."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"chest-tube-management",title:"Chest Tube Management for RTs",category:"Critical Care",seoTitle:"Chest Tube Management – Pneumothorax, Pleural Drainage | RRT",seoDescription:"Learn chest tube management: indications, water seal vs suction, air leak assessment, and RT responsibilities for the RRT exam.",seoKeywords:["chest tube","pleural drainage","water seal","air leak","pneumothorax","thoracostomy","RRT exam"],overview:"Chest tube (thoracostomy tube) management is a key respiratory therapy competency. Chest tubes drain air (pneumothorax), fluid (pleural effusion, hemothorax, empyema), or both from the pleural space to restore negative intrapleural pressure and lung expansion. Understanding the drainage system (water seal, suction control) and assessing for air leaks are essential RT skills.",mechanismPhysiology:"Three-chamber system: (1) Collection chamber — collects drainage, measures output. (2) Water seal chamber — acts as a one-way valve: air exits the pleural space through the water seal (bubbles) but cannot return (prevents re-entry of air). The water level oscillates with respiration ('tidaling'). (3) Suction control — wet suction (water column height determines suction level, typically −20 cmH2O) or dry suction (spring/regulator mechanism). Water seal alone allows passive drainage; suction provides active evacuation.",clinicalRelevance:"Pneumothorax: chest tube with suction until air leak resolves and lung is re-expanded, then transition to water seal. If lung remains expanded on water seal for 12–24 hours with no air leak → remove. Pleural effusion: large-bore tube for empyema/hemothorax, small-bore (pigtail) for simple effusions. RT responsibilities: maintain system below chest level, monitor drainage volume/character, assess air leak, ensure tidaling (confirms patency), troubleshoot alarms/problems, assist with removal.",signsSymptoms:"Pneumothorax indications for chest tube: symptomatic, large (> 2 cm apex-to-cupola distance), tension pneumothorax (emergency). Effusion indications: large symptomatic effusion, empyema, hemothorax. Signs of functioning system: tidaling (fluid oscillation with breathing), air bubbling through water seal (if air leak present), drainage output.",assessment:"Continuous monitoring: tidaling (should be present — absence suggests obstruction, kink, or full lung expansion), air leak (bubbling in water seal — quantify: continuous vs respiratory only, size 1–7 scale), drainage volume and character (sanguineous, serosanguineous, purulent), patient respiratory status, CXR for lung re-expansion. Concerning signs: sudden cessation of tidaling (possible clot, kink, or dislodgement), massive air leak (bronchopleural fistula or system disconnection), rapid bloody drainage > 200 mL/hour (hemothorax — surgical consult).",management:"Setup: maintain system below chest level at all times. Suction: typically −20 cmH2O. Do NOT clamp a chest tube with an active air leak (tension pneumothorax risk). Milking/stripping: controversial — may generate dangerously high negative pressure. Transport: keep system upright and below chest level, water seal is sufficient (do not need suction during transport). Accidental disconnection: submerge the tube end in sterile water (creates emergency water seal) or reconnect immediately. Removal: end-expiratory or during Valsalva maneuver, apply petroleum gauze dressing.",complications:"Infection (empyema, site infection), re-expansion pulmonary edema (rapid drainage of large effusion), hemorrhage, subcutaneous emphysema, tube dislodgement, pain, recurrent pneumothorax after removal.",clinicalPearls:["NEVER clamp a chest tube with an active air leak — can cause TENSION PNEUMOTHORAX","Absence of tidaling: check for kink/obstruction first, then consider full lung re-expansion","If chest tube disconnects: submerge the tube end in sterile water as an emergency water seal","Rapid bloody drainage > 200 mL/hour suggests active hemorrhage — notify surgeon immediately"],examPitfalls:["Clamping a chest tube when an air leak is present — can cause tension pneumothorax","Placing the drainage system above the patient's chest — allows fluid to drain back into pleural space","Not recognizing loss of tidaling as a potentially concerning sign","Aggressively stripping/milking chest tubes — generates dangerously high negative pressure"],faqJson:[{question:"What does tidaling indicate?",answer:"Tidaling (fluid oscillation in the water seal chamber with respiration) confirms the chest tube is patent and properly positioned in the pleural space. During spontaneous breathing: fluid rises with inspiration and falls with expiration. On mechanical ventilation: opposite pattern. Absence of tidaling may indicate tube obstruction, kinking, or complete lung re-expansion."},{question:"When should a chest tube be removed?",answer:"For pneumothorax: when there is no air leak, lung is fully re-expanded on CXR, and the patient has been on water seal for 12–24 hours without recurrence. For effusions: when drainage is < 150–200 mL/day and fluid is non-purulent."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"exercise-testing-cpet",title:"Cardiopulmonary Exercise Testing (CPET)",category:"Pulmonary Function Testing",seoTitle:"CPET – Cardiopulmonary Exercise Testing Interpretation | RRT",seoDescription:"Learn CPET: VO2max, anaerobic threshold, respiratory limitation patterns, and clinical applications for the RRT exam.",seoKeywords:["CPET","cardiopulmonary exercise testing","VO2max","anaerobic threshold","exercise limitation","dyspnea evaluation","RRT exam"],overview:"Cardiopulmonary exercise testing (CPET) simultaneously measures respiratory, cardiovascular, and metabolic responses to graded exercise. It is the gold standard for evaluating exercise intolerance and unexplained dyspnea. Key parameters include VO2max (maximal oxygen consumption), anaerobic threshold (AT), VE/VCO2 slope (ventilatory efficiency), and breathing reserve. CPET differentiates cardiac, pulmonary, deconditioning, and psychogenic exercise limitation.",mechanismPhysiology:"During incremental exercise, oxygen consumption (VO2) and CO2 production (VCO2) increase linearly until the anaerobic threshold (AT), after which VCO2 increases more rapidly (lactic acid buffered by HCO3 produces excess CO2). VO2max: highest achievable VO2, limited by the weakest link in the O2 transport chain (lungs → heart → muscles). Breathing reserve = MVV − peak VE (normal > 15–20 L/min or > 30% MVV). Low breathing reserve suggests ventilatory limitation. Dead space ventilation (VD/VT): normally decreases with exercise; failure to decrease suggests pulmonary vascular disease.",clinicalRelevance:"Patterns: (1) Cardiac limitation: low VO2max, low AT, abnormal O2 pulse (VO2/HR), ECG changes, normal breathing reserve. (2) Pulmonary limitation: low VO2max, low breathing reserve (< 15 L/min), desaturation, increased VD/VT, normal O2 pulse. (3) Deconditioning: low VO2max, early AT, normal breathing reserve, normal cardiovascular response, no desaturation. (4) Pulmonary vascular: increased VE/VCO2 slope, high VD/VT, desaturation, low VO2max. Pre-operative risk: VO2max < 10 mL/kg/min = high surgical risk, > 20 = low risk.",signsSymptoms:"Indications: unexplained dyspnea, exercise intolerance evaluation, pre-operative risk assessment (lung resection), disability evaluation, pulmonary rehabilitation prescription, treatment efficacy evaluation. Contraindications: acute MI, unstable angina, acute PE, severe aortic stenosis, uncontrolled arrhythmias, severe pulmonary hypertension.",assessment:"Collect: VO2 and VCO2 (breath-by-breath), ventilation (VE), heart rate, blood pressure, ECG, SpO2, work rate. Calculate: VO2max (mL/kg/min), AT (V-slope method or ventilatory equivalents), breathing reserve, O2 pulse, VE/VCO2 slope, VD/VT. Criteria for maximal effort: HR > 85% predicted max, RER > 1.10 (VCO2/VO2), symptoms limiting further exercise.",management:"Interpretation: systematic approach — (1) Was effort maximal? (2) Is VO2max normal or reduced? (3) What is the pattern of limitation (cardiac, pulmonary, deconditioning, vascular)? (4) Apply findings to clinical question (surgical risk, rehabilitation prescription, disability). Normal VO2max: > 84% predicted. AT normally occurs at 40–60% of predicted VO2max.",complications:"Exercise-related: cardiac arrhythmias, hypotension, syncope, bronchospasm, severe desaturation. Testing should be supervised by trained personnel with resuscitation equipment available.",clinicalPearls:["Breathing reserve < 15 L/min suggests pulmonary limitation to exercise","VO2max < 10 mL/kg/min = high surgical risk for lung resection","An elevated VE/VCO2 slope suggests pulmonary vascular disease or inefficient ventilation","AT normally occurs at 40–60% of VO2max — early AT suggests poor cardiovascular fitness or cardiac disease"],examPitfalls:["Not knowing what breathing reserve indicates (ventilatory limitation when low)","Confusing cardiac and pulmonary limitation patterns on CPET","Not understanding that VO2max reflects the integration of cardiac, pulmonary, and peripheral function","Forgetting that maximal effort criteria must be met for valid VO2max determination"],faqJson:[{question:"How does CPET differentiate cardiac from pulmonary exercise limitation?",answer:"Cardiac limitation: reduced VO2max with low O2 pulse and/or abnormal HR response, but NORMAL breathing reserve (lungs are not the limiting factor). Pulmonary limitation: reduced VO2max with LOW breathing reserve (< 15 L/min — using all available ventilatory capacity), often with desaturation."},{question:"What is the anaerobic threshold?",answer:"The exercise intensity at which anaerobic metabolism supplements aerobic metabolism, producing lactic acid. Identified on CPET as the point where VCO2 begins to increase disproportionately to VO2 (V-slope method). Early AT suggests cardiovascular limitation or deconditioning."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"inhaled-pulmonary-vasodilators",title:"Inhaled Pulmonary Vasodilators",category:"Pharmacology",seoTitle:"Inhaled Vasodilators – Nitric Oxide & Prostacyclins | RRT",seoDescription:"Learn inhaled pulmonary vasodilators: iNO, epoprostenol, iloprost, dosing, monitoring, and indications for the RRT exam.",seoKeywords:["inhaled nitric oxide","iNO","inhaled epoprostenol","iloprost","pulmonary vasodilator","selective vasodilation","RRT exam"],overview:"Inhaled pulmonary vasodilators selectively reduce pulmonary vascular resistance (PVR) by targeting ventilated lung units. They improve V/Q matching without systemic hypotension. Primary agents: inhaled nitric oxide (iNO) and inhaled prostacyclins (epoprostenol, iloprost). Key indications: PPHN, acute pulmonary hypertension, RV failure, refractory hypoxemia in ARDS, and pulmonary vasoreactivity testing.",mechanismPhysiology:"iNO: diffuses from alveoli into adjacent pulmonary vascular smooth muscle → activates guanylate cyclase → increases cGMP → smooth muscle relaxation → vasodilation. Rapidly inactivated by hemoglobin (forms methemoglobin) → no systemic effect. Inhaled prostacyclins: activate IP receptors on smooth muscle → increase cAMP → vasodilation and platelet inhibition. Both agents only reach VENTILATED alveoli → vasodilation occurs only where ventilation exists → improves V/Q matching.",clinicalRelevance:"iNO: FDA-approved for PPHN in neonates (starting dose 20 ppm). Off-label: ARDS (improves oxygenation transiently but no mortality benefit), cardiac surgery (RV failure), PH crisis. Inhaled epoprostenol: similar efficacy to iNO, significantly cheaper, delivered via continuous nebulization. Inhaled iloprost: longer half-life, intermittent nebulization (6–9 times daily for chronic PAH). Cost comparison: iNO is extremely expensive ($3,000–$5,000/day); inhaled epoprostenol is 1/10 the cost.",signsSymptoms:"Response indicators: improved SpO2/PaO2, decreased PA pressures (echo or PA catheter), improved RV function, decreased FiO2 requirement. Non-response: no improvement in oxygenation or PA pressures within 30–60 minutes. Adverse effects: methemoglobinemia (iNO — monitor q8–12h, keep < 5%), rebound PH on discontinuation (iNO), hypotension (prostacyclins — mild), flushing, headache.",assessment:"Baseline: SpO2, ABG, echocardiographic PA pressure estimate, FiO2 requirement. On therapy: SpO2 and ABG response within 30–60 minutes. iNO: methemoglobin level q8–12h (more frequently at doses > 20 ppm). Monitor NO2 levels (toxic byproduct — keep < 2 ppm). Prostacyclins: monitor systemic BP (mild systemic vasodilation possible), headache.",management:"iNO: start at 20 ppm (PPHN), 5–20 ppm (ARDS, PH). If no response at 20 ppm: increasing to 40 ppm rarely adds benefit — consider discontinuation. Weaning: decrease by 5 ppm to 5 ppm, then by 1 ppm, monitoring for rebound. Inhaled epoprostenol: 10,000–50,000 ng/mL in nebulizer, continuous delivery through ventilator circuit. Iloprost: 2.5–5 mcg per nebulization, 6–9 times daily. Delivery systems: inline continuous nebulization for ventilated patients (epoprostenol), specialized delivery devices (iNO — INOmax DSIR system).",complications:"iNO: methemoglobinemia (dose-dependent), rebound PH on discontinuation, NO2 toxicity (pulmonary edema), platelet dysfunction. Prostacyclins: systemic hypotension (mild), flushing, headache, jaw pain, platelet inhibition (bleeding risk).",clinicalPearls:["iNO improves oxygenation in ARDS but does NOT reduce mortality — use as a rescue therapy only","Inhaled epoprostenol is as effective as iNO at 1/10 the cost — increasingly used as first-line","iNO must be weaned slowly — abrupt discontinuation causes rebound pulmonary hypertension","Both agents are SELECTIVE because they only reach ventilated alveoli — improving V/Q matching"],examPitfalls:["Thinking iNO reduces mortality in ARDS — it improves oxygenation only","Abruptly discontinuing iNO without weaning","Not monitoring methemoglobin levels during iNO therapy","Not knowing that inhaled epoprostenol is a cost-effective alternative to iNO"],faqJson:[{question:"Why is iNO selective to the pulmonary vasculature?",answer:"iNO reaches only ventilated alveoli when inhaled, causing vasodilation only in perfused vessels adjacent to ventilated lung units. It is immediately inactivated when it contacts hemoglobin in the blood, preventing any systemic vasodilation."},{question:"Why is inhaled epoprostenol gaining popularity over iNO?",answer:"Inhaled epoprostenol has similar efficacy to iNO for improving oxygenation and reducing PVR, but costs approximately 1/10 as much ($300–500/day vs $3,000–5,000/day for iNO). It can be delivered through standard inline nebulizers."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"sleep-study-polysomnography",title:"Polysomnography (Sleep Study) Interpretation",category:"Sleep Medicine",seoTitle:"Polysomnography – Sleep Study Scoring & Interpretation | RRT",seoDescription:"Learn polysomnography: channels, scoring rules, AHI interpretation, and sleep architecture for the RRT exam.",seoKeywords:["polysomnography","PSG","sleep study","AHI","apnea hypopnea index","sleep stages","RRT exam"],overview:"Polysomnography (PSG) is the gold standard diagnostic test for sleep-disordered breathing. It simultaneously records EEG (brain waves), EOG (eye movements), EMG (muscle tone), ECG, airflow (nasal pressure transducer + thermistor), respiratory effort (chest and abdominal bands), SpO2, body position, and snoring. The RT/sleep technologist scores events, stages sleep, and calculates the apnea-hypopnea index (AHI).",mechanismPhysiology:"Sleep architecture: sleep progresses through stages — N1 (light sleep, 5%), N2 (intermediate, 45%), N3 (deep/slow-wave, 25%), and REM (dreaming, 25%). REM sleep has the greatest upper airway muscle atonia → most apneas/hypopneas occur during REM. Sleep cycles repeat every 90 minutes with increasing REM proportion later in the night. Scoring: Apnea = cessation of airflow ≥ 90% reduction for ≥ 10 seconds. Hypopnea = ≥ 30% reduction in airflow for ≥ 10 seconds with either ≥ 3% desaturation or arousal. AHI = (apneas + hypopneas) / total sleep hours.",clinicalRelevance:"AHI classification: < 5 = normal, 5–14 = mild OSA, 15–29 = moderate OSA, ≥ 30 = severe OSA. RDI (respiratory disturbance index) includes RERAs (respiratory effort-related arousals). Split-night study: diagnostic PSG in first half → if AHI > 40 (or > 20 with clinical indication), CPAP titration in second half. Home sleep apnea testing (HSAT): alternative for uncomplicated OSA (no significant comorbidities, high pretest probability). HSAT underestimates AHI because it uses recording time, not sleep time, as the denominator.",signsSymptoms:"Indications for PSG: suspected OSA, central sleep apnea evaluation, narcolepsy (followed by MSLT), parasomnias, periodic limb movement disorder, CPAP titration, preoperative evaluation in suspected SDB. Findings: obstructive events show continued/increased respiratory effort with absent airflow; central events show absent effort AND airflow; mixed events begin central and become obstructive.",assessment:"Scoring: stage sleep per AASM rules, identify and classify respiratory events (obstructive, central, mixed, hypopnea, RERA), count periodic limb movements, calculate AHI, RDI, PLM index, oxygen desaturation index (ODI), minimum SpO2, time with SpO2 < 90%. Report: sleep efficiency, sleep latency, REM latency, AHI (total, supine, REM), oxygen metrics, cardiac findings.",management:"Mild OSA (AHI 5–14): positional therapy, weight loss, oral appliance, or CPAP depending on symptoms. Moderate OSA (15–29): CPAP (first-line), oral appliance if CPAP intolerant. Severe OSA (≥ 30): CPAP strongly recommended. CPAP titration: start at 4 cmH2O, increase by 1 cmH2O to eliminate apneas, hypopneas, snoring, and desaturations. Auto-CPAP: adjusts pressure automatically (4–20 cmH2O range) — alternative to in-lab titration.",complications:"Untreated OSA: hypertension, atrial fibrillation, stroke, MI, motor vehicle accidents, cognitive impairment, depression. CPAP side effects: mask discomfort, aerophagia, nasal congestion, skin breakdown, claustrophobia.",clinicalPearls:["AHI ≥ 5 with symptoms (or ≥ 15 regardless of symptoms) meets diagnostic criteria for OSA","REM-related OSA: if events cluster in REM, the overall AHI may underestimate severity — report REM AHI separately","HSAT underestimates AHI — a negative HSAT does not rule out OSA if clinical suspicion is high","Split-night study saves time and cost but requires adequate diagnostic time (≥ 2 hours) in the first half"],examPitfalls:["Confusing AHI severity classifications (mild 5–14, moderate 15–29, severe ≥ 30)","Not knowing the definitions of apnea (≥ 90% airflow reduction for ≥ 10 seconds) and hypopnea (≥ 30% reduction with desaturation or arousal)","Thinking HSAT is equivalent to PSG — it underestimates severity and cannot stage sleep","Not distinguishing obstructive (effort present) from central (effort absent) events"],faqJson:[{question:"What is the difference between AHI and RDI?",answer:"AHI includes apneas and hypopneas only. RDI includes apneas, hypopneas, AND respiratory effort-related arousals (RERAs). RDI is always ≥ AHI. Some diagnostic criteria use AHI, others use RDI — know which your facility uses."},{question:"What is a split-night study?",answer:"The first half of the night is diagnostic PSG. If the AHI is ≥ 40 (or ≥ 20 with clinical discretion) and at least 2 hours of diagnostic data are obtained, the second half is used for CPAP titration. This saves the patient from returning for a separate titration night."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"capnography-monitoring",title:"Capnography & End-Tidal CO2 Monitoring",category:"Patient Assessment",seoTitle:"Capnography – ETCO2 Waveform Interpretation & Monitoring | RRT",seoDescription:"Learn capnography: ETCO2 monitoring, waveform interpretation, clinical applications, and abnormal patterns for the RRT exam.",seoKeywords:["capnography","ETCO2","end-tidal CO2","waveform","capnogram","mainstream","sidestream","RRT exam"],overview:"Capnography is the continuous monitoring and graphical display of exhaled CO2 concentration over time. End-tidal CO2 (ETCO2) is the CO2 level at the end of exhalation, normally 35–45 mmHg (approximately 2–5 mmHg below PaCO2). Capnography provides real-time assessment of ventilation, perfusion, and metabolism. It is considered standard of care during procedural sedation, intubation confirmation, and CPR quality monitoring.",mechanismPhysiology:"Normal capnogram phases: Phase I — dead space gas (no CO2, inspiration). Phase II — mixing of dead space and alveolar gas (sharp upstroke). Phase III — alveolar plateau (CO2 from alveoli, should be relatively flat). End-tidal point: the highest CO2 at end of Phase III = ETCO2. Phase 0 — inspiratory downstroke (CO2 drops to zero). ETCO2 approximates PaCO2 (normally ETCO2 is 2–5 mmHg less than PaCO2). The PaCO2-ETCO2 gradient increases with dead space ventilation (PE, COPD, low CO).",clinicalRelevance:"Clinical applications: (1) Intubation confirmation — GOLD STANDARD (detection of CO2 confirms tracheal placement; absence suggests esophageal). (2) CPR quality — ETCO2 > 20 mmHg during compressions suggests adequate CPR quality; sudden rise to > 40 suggests ROSC. (3) Ventilation monitoring — continuous trend; increasing ETCO2 = hypoventilation, decreasing = hyperventilation. (4) Bronchospasm — 'shark fin' waveform (prolonged Phase III upslope). (5) Circuit disconnect — sudden drop to zero.",signsSymptoms:"Abnormal waveform patterns: Shark fin (bronchospasm): prolonged sloping Phase III from uneven alveolar emptying. Rebreathing: elevated Phase I baseline (CO2 doesn't reach zero — inadequate expiratory valve, exhausted CO2 absorber). Curare cleft: small notch in Phase III plateau from spontaneous breathing effort during neuromuscular blockade wearing off. Sudden drop to zero: circuit disconnect, ET tube displacement, cardiac arrest. Gradual decline: decreasing cardiac output, hypothermia, hyperventilation.",assessment:"Monitor: ETCO2 value (trending), waveform shape, respiratory rate. Alarm settings: low ETCO2 (< 20 — disconnect, hyperventilation, cardiac arrest), high ETCO2 (> 50 — hypoventilation, MH, increased metabolism). Calculate PaCO2-ETCO2 gradient: normally 2–5 mmHg. Increased gradient suggests increased dead space (PE, COPD, low CO, emphysema).",management:"Elevated ETCO2: increase ventilation (increase RR or Vt), assess for MH (rapidly rising ETCO2 with tachycardia, muscle rigidity), check for rebreathing. Low ETCO2: check for disconnection, verify ET tube position, assess cardiac output (low CO → low ETCO2), check for hyperventilation. During CPR: target ETCO2 > 20 mmHg with compressions, sudden rise may indicate ROSC. Waveform analysis: use pattern recognition to identify specific clinical conditions.",complications:"False readings from: contamination with anesthetic gases, water in sampling line (sidestream), mouth breathing around ET tube, high FiO2 dilution (some analyzers). Sidestream: delayed reading (transit time), sampling line occlusion. Mainstream: heavy sensor on ET tube, may cause tube movement.",clinicalPearls:["ETCO2 is the GOLD STANDARD for confirming ET tube placement — more reliable than auscultation","During CPR: ETCO2 > 20 mmHg indicates effective compressions; sudden rise > 40 suggests ROSC","The 'shark fin' capnogram waveform indicates bronchospasm — administer bronchodilator","An increasing PaCO2-ETCO2 gradient suggests increasing dead space — consider PE if acute"],examPitfalls:["Not using capnography to confirm ET tube placement — it is the GOLD STANDARD","Not recognizing the 'shark fin' waveform as bronchospasm","Thinking ETCO2 = PaCO2 — there is normally a 2–5 mmHg gradient","Not monitoring ETCO2 during procedural sedation — it is standard of care"],faqJson:[{question:"Why is ETCO2 the gold standard for confirming ET tube placement?",answer:"CO2 is only produced by the lungs — detection of sustained CO2 on capnography confirms the tube is in the trachea. Esophageal intubation produces no CO2 (or a brief few breaths of swallowed gas that quickly disappears). No other method (auscultation, chest rise, fogging) is as reliable."},{question:"What does ETCO2 indicate during CPR?",answer:"ETCO2 reflects cardiac output during CPR (CO2 transport to lungs requires perfusion). ETCO2 > 20 mmHg suggests adequate compression quality. ETCO2 < 10 mmHg after 20 minutes of CPR is associated with very poor survival. A sudden sustained rise in ETCO2 may indicate return of spontaneous circulation (ROSC)."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"copd-acute-exacerbation",title:"COPD Acute Exacerbation Management",category:"COPD Management",seoTitle:"COPD Exacerbation – Acute Management & NIV for RT | RRT",seoDescription:"Learn COPD acute exacerbation management: bronchodilators, steroids, antibiotics, NIV indications, and ABG monitoring for the RRT exam.",seoKeywords:["COPD exacerbation","AECOPD","NIV COPD","BiPAP","bronchodilator","systemic steroids","RRT exam"],overview:"Acute exacerbation of COPD (AECOPD) is a sustained worsening of respiratory symptoms beyond normal day-to-day variation requiring change in medication. It is the leading cause of COPD hospitalization and a major contributor to disease progression. Management pillars: bronchodilators, systemic corticosteroids, antibiotics (if indicated), and non-invasive ventilation (NIV) for respiratory acidosis. NIV in COPD exacerbation has the strongest evidence base in all of medicine.",mechanismPhysiology:"Triggers: viral infection (most common — rhinovirus, influenza), bacterial infection (H. influenzae, M. catarrhalis, S. pneumoniae, P. aeruginosa in severe COPD), air pollution, cold air, medication non-adherence. Pathophysiology: increased airway inflammation → bronchospasm → mucus hypersecretion → air trapping → V/Q mismatch → hypoxemia and hypercapnia → respiratory acidosis → respiratory muscle fatigue → respiratory failure.",clinicalRelevance:"NIV indication (strongest evidence in medicine): pH < 7.35 and PaCO2 > 45 (acute or acute-on-chronic respiratory acidosis). NIV reduces intubation by 65%, reduces mortality by 50%, and reduces ICU stay. Start immediately — do not wait for ABG trends. Typical settings: IPAP 10–20 cmH2O, EPAP 4–6 cmH2O, target Vt 6–8 mL/kg. Reassess within 1–2 hours — if no improvement (pH not improving, mental status worsening), proceed to intubation.",signsSymptoms:"Cardinal symptoms: increased dyspnea, increased sputum volume, increased sputum purulence. Severity classification: mild (1 cardinal symptom), moderate (2 cardinal symptoms), severe (3 cardinal symptoms or any requiring hospitalization). Signs of severe exacerbation: use of accessory muscles, paradoxical breathing, cyanosis, altered mental status, peripheral edema (cor pulmonale), hemodynamic instability.",assessment:"ABG: essential — determines need for NIV (pH < 7.35 with PaCO2 > 45). Distinguish acute from acute-on-chronic: check HCO3 (elevated HCO3 with acute pH drop = acute-on-chronic). CXR: rule out pneumonia, pneumothorax, pleural effusion. Labs: CBC, BMP, procalcitonin (guides antibiotic use), BNP (if cardiac component suspected). SpO2 target: 88–92% (avoid hyperoxia → worsens hypercapnia).",management:"Bronchodilators: albuterol + ipratropium via nebulizer q2–4h (or more frequently). Systemic corticosteroids: prednisone 40 mg × 5 days (REDUCE trial — 5 days equally effective as 14). Antibiotics: if ≥ 2 cardinal symptoms or 1 with increased purulence — amoxicillin/clavulanate, azithromycin, or fluoroquinolone × 5–7 days. Controlled oxygen: target SpO2 88–92% via Venturi mask (precise delivery). NIV: for pH < 7.35 and PaCO2 > 45 — IPAP 10–20, EPAP 4–6, reassess in 1–2 hours. Intubation: if NIV fails (worsening pH, declining mental status) or contraindicated.",complications:"Intubation and mechanical ventilation (poor prognosis in COPD), nosocomial infections, oxygen-induced hypercapnia, cardiac arrhythmias, VTE, deconditioning, death (in-hospital mortality 3–10%, 1-year mortality 25–30%).",clinicalPearls:["NIV in COPD exacerbation has the STRONGEST evidence in all of NIV — reduces intubation by 65%","Target SpO2 88–92% in COPD — hyperoxia worsens hypercapnia through multiple mechanisms","5 days of systemic steroids is equally effective as 14 days (REDUCE trial)","Check ABG within 1–2 hours of starting NIV — if pH is not improving, consider intubation"],examPitfalls:["Over-oxygenating COPD patients — target 88–92%, use Venturi mask for precision","Delaying NIV when pH < 7.35 — start immediately, don't wait for 'trends'","Prescribing 14 days of steroids — 5 days is equally effective","Not reassessing ABG within 1–2 hours of NIV initiation"],faqJson:[{question:"Why does oxygen worsen hypercapnia in COPD?",answer:"Multiple mechanisms: (1) Haldane effect — oxygen displaces CO2 from hemoglobin, raising dissolved CO2. (2) V/Q mismatch worsening — O2 reverses hypoxic vasoconstriction in poorly ventilated areas, increasing perfusion to areas that can't effectively ventilate. (3) Reduced hypoxic drive (minor contributor). The Haldane effect and V/Q worsening are the primary mechanisms."},{question:"What are the NIV criteria for COPD exacerbation?",answer:"pH < 7.35 with PaCO2 > 45 mmHg (respiratory acidosis). NIV should be initiated immediately — it reduces intubation by 65% and mortality by 50%. Typical settings: IPAP 10–20, EPAP 4–6. Reassess in 1–2 hours with repeat ABG."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"lung-transplant-respiratory",title:"Lung Transplant Respiratory Management",category:"Pulmonary Rehabilitation",seoTitle:"Lung Transplant – Pre/Post Operative RT Management | RRT",seoDescription:"Learn lung transplant respiratory management: pre-operative evaluation, post-operative ventilation, immunosuppression complications, and rehabilitation for the RRT exam.",seoKeywords:["lung transplant","post-transplant","BOS","CLAD","rejection","pulmonary rehabilitation","RRT exam"],overview:"Lung transplantation is the definitive treatment for end-stage lung disease (COPD, IPF, CF, PAH). Respiratory therapists manage pre-transplant optimization, post-operative ventilator management, secretion clearance, pulmonary rehabilitation, and monitoring for complications (rejection, infection). Chronic lung allograft dysfunction (CLAD) affects 50% of recipients by 5 years and remains the major long-term challenge.",mechanismPhysiology:"Transplant types: single lung, bilateral sequential, heart-lung. Post-transplant physiology: denervated lungs (absent cough reflex below anastomosis, reduced mucociliary clearance), impaired lymphatic drainage (increased susceptibility to pulmonary edema), ischemia-reperfusion injury (primary graft dysfunction in early post-operative period). Immunosuppression: required lifelong — triple therapy (calcineurin inhibitor + antimetabolite + corticosteroid). Chronic rejection (CLAD/BOS): obliterative bronchiolitis — progressive airflow obstruction from fibrotic small airway obliteration.",clinicalRelevance:"RT role pre-transplant: pulmonary rehabilitation (optimize functional status), education on post-transplant expectations, airway clearance techniques (CF patients). Post-operative: ventilator management (lung-protective, avoid overdistension — fragile anastomosis), suctioning (impaired cough reflex — may need aggressive airway clearance), early mobilization and rehabilitation. Monitor FEV1 trend: decline > 20% from baseline suggests CLAD/BOS — requires urgent evaluation.",signsSymptoms:"Post-transplant complications: primary graft dysfunction (first 72 hours — ARDS-like picture), acute rejection (dyspnea, cough, fever, FEV1 decline — biopsy confirms), infection (leading cause of early death — CMV, Aspergillus, Pneumocystis), chronic rejection/CLAD (progressive dyspnea, declining FEV1, airflow obstruction). Monitoring schedule: spirometry at home (daily or weekly FEV1), clinic visits with PFTs, surveillance bronchoscopy with biopsy.",assessment:"Post-operative: ventilator weaning assessment (may be prolonged due to deconditioning), chest tube management (bilateral if bilateral transplant), CXR for lung expansion and complications. Ongoing: spirometry at every clinic visit and at home (FEV1 trend), monitor for infection symptoms, bronchoscopy with BAL and biopsy for rejection/infection surveillance. Blood work: drug levels (tacrolimus/cyclosporine), CMV PCR.",management:"Post-operative ventilation: lung-protective settings, early extubation when possible. Airway clearance: aggressive — denervated lungs have impaired mucociliary clearance and no cough reflex below the anastomosis. Pulmonary rehabilitation: start early, progressive exercise program (significant deconditioning from pre-transplant illness). Infection prophylaxis: antiviral (ganciclovir/valganciclovir for CMV), antifungal (voriconazole/itraconazole), anti-PJP (TMP-SMX). CLAD/BOS treatment: augment immunosuppression, azithromycin (anti-inflammatory), re-transplant for progressive decline.",complications:"Primary graft dysfunction, acute rejection, chronic rejection (CLAD/BOS), infection (CMV, Aspergillus, PJP), malignancy (immunosuppression-related — skin cancer, PTLD), renal dysfunction (calcineurin inhibitors), osteoporosis, diabetes.",clinicalPearls:["Post-transplant lungs are DENERVATED — the cough reflex is absent below the anastomosis; aggressive airway clearance is essential","A decline in FEV1 > 20% from baseline is the hallmark of chronic rejection (CLAD/BOS) — report immediately","Infection is the leading cause of death in the first year — monitor closely and prophylax aggressively","Early and progressive pulmonary rehabilitation significantly improves post-transplant outcomes"],examPitfalls:["Not knowing that transplanted lungs lack a cough reflex below the anastomosis","Forgetting that infection (not rejection) is the leading cause of early death","Not monitoring FEV1 trends for early detection of chronic rejection","Using excessive ventilator pressures post-transplant — fragile bronchial anastomosis"],faqJson:[{question:"What is chronic lung allograft dysfunction (CLAD)?",answer:"CLAD is a persistent decline in FEV1 > 20% from the post-transplant baseline that persists for ≥ 3 months without other identifiable cause. The most common form is bronchiolitis obliterans syndrome (BOS) — progressive fibrotic obliteration of small airways causing obstructive physiology. It affects ~50% of recipients by 5 years."},{question:"Why is aggressive airway clearance needed after lung transplant?",answer:"Transplanted lungs are denervated — the vagal innervation is cut during surgery. This means: (1) the cough reflex is absent below the anastomosis (secretions cannot be cleared by cough), (2) mucociliary clearance is impaired, (3) lymphatic drainage is disrupted. Without aggressive airway clearance, retained secretions lead to mucus plugging, atelectasis, and infection."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ppe-respiratory-protection",title:"PPE & Respiratory Protection for RTs",category:"Infection Control",seoTitle:"PPE & Respiratory Protection – N95, PAPR & AGPs | RRT",seoDescription:"Learn PPE and respiratory protection: N95 vs surgical mask, PAPR, aerosol-generating procedures, and infection control for the RRT exam.",seoKeywords:["PPE","N95 respirator","PAPR","aerosol generating procedures","AGP","infection control","respiratory protection","RRT exam"],overview:"Respiratory therapists perform the highest proportion of aerosol-generating procedures (AGPs) among healthcare workers, making proper PPE selection and use critical. RTs must understand the hierarchy of respiratory protection (surgical mask → N95 → PAPR/CAPR), aerosol-generating procedures requiring enhanced protection, and proper donning/doffing procedures to prevent self-contamination.",mechanismPhysiology:"Respiratory pathogen transmission: droplet (> 5 μm, travel < 6 feet, settle quickly), airborne (< 5 μm/droplet nuclei, remain suspended, travel far — TB, measles, varicella, COVID-19 during AGPs). N95 respirator: filters ≥ 95% of 0.3 μm particles (the most penetrating particle size — actually more efficient for both smaller and larger particles). Surgical mask: filters large droplets but does NOT provide a seal — does not protect against airborne transmission. PAPR (powered air-purifying respirator): motorized unit provides filtered air under positive pressure — does not require fit testing, higher protection factor.",clinicalRelevance:"Aerosol-generating procedures (RT-performed): intubation/extubation, bag-mask ventilation, open suctioning, nebulizer therapy, high-flow nasal cannula, CPAP/BiPAP, bronchoscopy, CPR, sputum induction, tracheostomy care. These procedures generate small respirable particles that can carry pathogens. Minimum N95 (or PAPR) required for AGPs with airborne/aerosol-transmissible pathogens. N95 requires annual fit testing and user seal check before EACH use.",signsSymptoms:"Signs of improper PPE: fogging of eyewear with N95 (seal leak), air movement around mask edges during breathing, improper donning sequence (missing steps), touching the front of the mask (contaminated surface), improper doffing sequence (most contamination occurs during removal).",assessment:"Pre-use: verify N95 fit test is current (annual), perform user seal check (positive and negative pressure test before each use). PAPR: verify filter integrity, battery charge, flow rate. PPE selection: standard precautions (minimum), contact (gown + gloves), droplet (surgical mask + eye protection), airborne (N95 + eye protection + negative pressure room), AGP with airborne pathogen (N95 or PAPR + eye protection + gown + gloves).",management:"Donning sequence: hand hygiene → gown → N95/PAPR → eye protection → gloves. Doffing sequence (CRITICAL — most exposure occurs here): gloves (most contaminated, remove first) → eye protection → gown → hand hygiene → N95/PAPR → hand hygiene. N95 user seal check: cover respirator with hands, exhale sharply (positive pressure — no air leak around edges) and inhale sharply (negative pressure — respirator collapses slightly). Reuse/extended use protocols per facility policy.",complications:"Healthcare worker infection from improper PPE, skin breakdown from prolonged N95 use, heat stress from PAPR, communication difficulties, patient anxiety from masked providers, PPE fatigue/non-compliance during prolonged outbreaks.",clinicalPearls:["RTs perform MORE aerosol-generating procedures than any other healthcare discipline — PPE is critical","N95 requires fit testing ANNUALLY and a user seal check before EVERY use","Most contamination occurs during DOFFING (removal) — follow proper sequence carefully","Open suctioning, nebulization, and bag-mask ventilation are ALL aerosol-generating procedures"],examPitfalls:["Not knowing which procedures are aerosol-generating (most RT procedures ARE)","Confusing surgical mask protection (droplets only) with N95 protection (airborne particles)","Not performing user seal check before each N95 use","Incorrect doffing sequence — most self-contamination occurs during removal"],faqJson:[{question:"What is the difference between an N95 and a surgical mask?",answer:"An N95 filters ≥ 95% of 0.3 μm airborne particles AND provides a tight facial seal — protecting against both droplet and airborne transmission. A surgical mask filters large droplets but does NOT seal to the face — it protects against droplets only. N95s require annual fit testing."},{question:"What are aerosol-generating procedures?",answer:"Procedures that generate small respirable particles (< 5 μm) that can carry pathogens: intubation, extubation, bag-mask ventilation, open suctioning, nebulizer therapy, HFNC, CPAP/BiPAP, bronchoscopy, CPR, sputum induction, and tracheostomy care. Enhanced respiratory protection (N95 minimum) is required."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ards-prone-positioning-protocol",title:"Prone Positioning Protocol for ARDS",category:"ARDS",seoTitle:"Prone Positioning – ARDS Protocol, Duration & Evidence | RRT",seoDescription:"Learn prone positioning for ARDS: PROSEVA protocol, indications, contraindications, team coordination, and oxygenation improvement for the RRT exam.",seoKeywords:["prone positioning","ARDS","PROSEVA","prone ventilation","oxygenation","lung recruitment","RRT exam"],overview:"Prone positioning is a proven intervention that reduces mortality in moderate-severe ARDS (PROSEVA trial: 28-day mortality 16% prone vs 33% supine). It improves oxygenation by redistributing lung perfusion, recruiting dorsal atelectatic lung, improving V/Q matching, and reducing VILI. Current guidelines recommend prone positioning for ≥ 16 hours/day in patients with P/F < 150 despite optimal ventilator settings.",mechanismPhysiology:"In supine ARDS: dependent (dorsal) lung is compressed by the weight of edematous lung tissue, heart, and abdominal contents → dorsal atelectasis. Ventilation goes preferentially to non-dependent (ventral) areas, but perfusion remains gravity-dependent (dorsal) → severe V/Q mismatch. In prone: (1) dorsal lung is no longer compressed → recruitment, (2) ventilation becomes more homogeneous (chest wall shape change), (3) heart weight no longer compresses left lower lobe, (4) functional residual capacity increases, (5) secretion drainage improves. Net effect: more homogeneous ventilation + maintained dorsal perfusion = improved V/Q matching.",clinicalRelevance:"PROSEVA trial (2013): moderate-severe ARDS (P/F < 150), prone ≥ 16 hours/day → NNT = 6 (1 life saved for every 6 patients proned). This is one of the strongest mortality benefits in critical care. Timing: early proning (within 12–24 hours of meeting criteria) provides the most benefit. Duration: ≥ 16 consecutive hours per session, continue until P/F > 150 on FiO2 ≤ 0.60 and PEEP ≤ 10 in supine position. RT role: manage ET tube security, ventilator management during turns, monitoring during prone sessions.",signsSymptoms:"Candidates: moderate-severe ARDS (P/F < 150 on FiO2 ≥ 0.60 and PEEP ≥ 5) despite 12–24 hours of optimal ventilator management. Contraindications: unstable spine/pelvic fractures, open abdomen, raised ICP (relative), recent sternotomy (relative), massive hemoptysis, facial trauma/surgery. Complications to monitor during prone: ET tube displacement, pressure injuries (face, chest), abdominal compression, hemodynamic instability.",assessment:"Before proning: secure all tubes and lines, verify ET tube position and security, document current ventilator settings and ABG, eye care (lubricant and tape), head-of-bed positioning plan. During prone: continuous SpO2, check ET tube position immediately after turn, assess hemodynamics, reassess ventilator settings (may need PEEP adjustment). ABG 1 hour after proning: if P/F increases > 20, the patient is a 'responder' — continue. After supinating: ABG to assess for sustained improvement.",management:"Procedure: team of 5–6 (RT manages airway), pre-check all equipment, turn in coordinated movement. During prone: head turned to side, arms in 'swimmer' position (changed q2h to prevent plexopathy), pressure relief for face/chest (foam positioning aids). Ventilator during prone: may need to reduce PEEP slightly (improved compliance), Vt remains 6 mL/kg IBW, continue lung-protective strategy. Stopping criteria: P/F > 150 on FiO2 ≤ 0.60 and PEEP ≤ 10 when checked in supine position.",complications:"Accidental extubation during turn (most feared — RT must control airway), pressure injuries (face, anterior chest, iliac crests), brachial plexus injury, vomiting/aspiration, hemodynamic instability, corneal injury, peripheral nerve injury, circuit disconnection.",clinicalPearls:["PROSEVA: NNT = 6 — one of the strongest mortality benefits in ARDS management","Prone for ≥ 16 hours per session — longer duration provides more benefit","The RT manages the AIRWAY during prone turns — this is the most critical role","If P/F improves > 20 after 1 hour of proning, the patient is a 'responder' — continue therapy"],examPitfalls:["Not knowing the PROSEVA criteria (P/F < 150 on FiO2 ≥ 0.60, PEEP ≥ 5)","Proning for less than 16 hours — insufficient duration","Not securing the ET tube before turning — accidental extubation is the most feared complication","Stopping prone positioning too early — continue until sustained supine improvement"],faqJson:[{question:"How does prone positioning improve oxygenation?",answer:"Prone positioning recruits previously compressed dorsal lung, redistributes ventilation more homogeneously while maintaining gravity-dependent dorsal perfusion, relieves cardiac compression of the left lower lobe, and increases FRC. The net result is improved V/Q matching and oxygenation."},{question:"When should prone positioning be stopped?",answer:"When the patient demonstrates sustained improvement in supine position: P/F > 150 on FiO2 ≤ 0.60 and PEEP ≤ 10. Check by briefly supinating the patient and assessing ABG. Also stop if severe complications occur (e.g., cardiac arrest, extubation during proning)."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"interstitial-lung-disease",title:"Interstitial Lung Disease Overview",category:"Patient Assessment",seoTitle:"Interstitial Lung Disease – Restrictive Pattern & RT Assessment | RRT",seoDescription:"Learn interstitial lung disease: restrictive PFT pattern, types (IPF, sarcoidosis), DLCO reduction, and respiratory management for the RRT exam.",seoKeywords:["interstitial lung disease","ILD","restrictive pattern","IPF","sarcoidosis","DLCO","pulmonary fibrosis","RRT exam"],overview:"Interstitial lung diseases (ILDs) are a group of diffuse parenchymal lung disorders affecting the alveolar walls, surrounding tissue, and interstitium. They cause a restrictive pattern on PFTs (reduced TLC, FVC with preserved or elevated FEV1/FVC ratio) and reduced DLCO (impaired gas transfer). Major types: idiopathic pulmonary fibrosis (IPF), sarcoidosis, hypersensitivity pneumonitis, connective tissue disease-associated ILD, drug-induced, and occupational (asbestosis, silicosis).",mechanismPhysiology:"ILD pathophysiology: inflammation and/or fibrosis of the lung interstitium → thickened alveolar-capillary membrane → reduced gas exchange (DLCO↓) → reduced lung compliance → restrictive physiology (reduced TLC, FVC). IPF: progressive fibrotic ILD with usual interstitial pneumonia (UIP) pattern on CT — honeycombing, traction bronchiectasis, basal predominance. Median survival 3–5 years without treatment. Sarcoidosis: non-caseating granulomas — may spontaneously resolve (Stage I-II) or progress to fibrosis (Stage IV).",clinicalRelevance:"PFT pattern: FVC reduced, TLC reduced, FEV1/FVC normal or increased (> 0.70 — not obstructive), DLCO reduced (hallmark of ILD — impaired gas transfer). IPF treatment: antifibrotic agents (pirfenidone, nintedanib) slow progression but do not reverse fibrosis. Sarcoidosis: corticosteroids for symptomatic or progressive disease. Oxygen therapy: supplemental O2 for resting or exertional hypoxemia. Pulmonary rehabilitation improves functional capacity and quality of life. Lung transplant: definitive treatment for progressive ILD.",signsSymptoms:"Progressive dyspnea on exertion (most common symptom), dry non-productive cough, clubbing (IPF — 50%), inspiratory crackles (fine, Velcro-like — characteristic), fatigue, weight loss. Sarcoidosis: may include bilateral hilar lymphadenopathy (CXR), skin lesions (erythema nodosum), uveitis, hypercalcemia.",assessment:"PFTs: restrictive pattern (TLC < 80% predicted), FVC reduced, FEV1/FVC normal or elevated, DLCO reduced (often earliest abnormality). HRCT chest: pattern recognition (UIP = basal honeycombing for IPF, ground glass for NSIP, upper lobe predominance for HP/sarcoidosis). 6MWT: functional assessment, desaturation with exertion. ABG: hypoxemia (initially exertional, later at rest), normal or low PaCO2 (until end-stage). Serum markers: ACE level (sarcoidosis — elevated but non-specific).",management:"Oxygen therapy: supplemental O2 for SpO2 < 88% at rest or with exertion (per LTOT criteria). Pulmonary rehabilitation: exercise training, education, psychosocial support — improves exercise tolerance and QoL. IPF: antifibrotic therapy (pirfenidone or nintedanib), cough management, GERD treatment (may worsen IPF). Sarcoidosis: observation if asymptomatic Stage I-II, corticosteroids if symptomatic/progressive. Advanced disease: lung transplant evaluation when FVC < 80% or DLCO < 40% with decline trajectory. Avoid: high-dose steroids in IPF (not effective, harmful).",complications:"Progressive respiratory failure, pulmonary hypertension (cor pulmonale — 30–40% of IPF patients), acute exacerbations (IPF — rapid decline with high mortality), opportunistic infections (immunosuppression treatment), lung cancer (increased risk in IPF).",clinicalPearls:["ILD shows a RESTRICTIVE pattern: reduced TLC, FVC with NORMAL or INCREASED FEV1/FVC ratio","DLCO is often the EARLIEST abnormality in ILD — reduced before spirometric changes","Fine, inspiratory Velcro-like crackles are characteristic of pulmonary fibrosis","IPF has NO effective cure — antifibrotics slow progression, lung transplant is the definitive treatment"],examPitfalls:["Confusing restrictive (ILD) with obstructive (COPD/asthma) PFT patterns","Not recognizing that a NORMAL or elevated FEV1/FVC ratio does NOT mean normal lungs — it may indicate restriction","Treating IPF with high-dose steroids — they are not effective and are harmful","Not checking DLCO when evaluating dyspnea — it may be the only abnormality in early ILD"],faqJson:[{question:"How is restrictive disease differentiated from obstructive on PFTs?",answer:"Restrictive: FVC reduced, FEV1 reduced proportionally, FEV1/FVC normal or ELEVATED (> 0.70), TLC reduced. Obstructive: FEV1 reduced disproportionately, FEV1/FVC reduced (< 0.70), TLC normal or increased (air trapping). DLCO is reduced in ILD (thickened membrane) and in emphysema (lost surface area)."},{question:"What is the UIP pattern on CT?",answer:"Usual Interstitial Pneumonia pattern: basal-predominant honeycombing (clusters of cystic airspaces with thick walls), traction bronchiectasis, reticulation, and minimal ground glass opacity. UIP pattern on HRCT in the appropriate clinical context (older adult, no identifiable cause) is sufficient for IPF diagnosis without biopsy."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"patient-education-respiratory",title:"Patient Education in Respiratory Care",category:"Patient Assessment",seoTitle:"Patient Education – Teach-Back, Health Literacy & RT Role | RRT",seoDescription:"Master patient education: teach-back method, health literacy assessment, disease management education, and communication strategies for the RRT exam.",seoKeywords:["patient education","teach-back","health literacy","self-management","inhaler technique","disease education","RRT exam"],overview:"Patient education is a core respiratory therapy competency. Effective education improves medication adherence, inhaler technique, self-management of chronic disease, and reduces hospitalization. The teach-back method is the gold standard for assessing understanding. Health literacy assessment ensures education materials match the patient's comprehension level. Key education topics: inhaler technique, oxygen safety, disease self-management, smoking cessation, and action plans.",mechanismPhysiology:"Adult learning principles: (1) Adults learn best when information is relevant to their immediate needs. (2) Build on existing knowledge. (3) Use multiple modalities (verbal + written + demonstration). (4) Practice skills (return demonstration). (5) Limit information to 3–5 key points per session (cognitive load theory). Health literacy: the ability to obtain, process, and understand basic health information. Low health literacy affects 36% of US adults and is associated with worse outcomes, higher hospitalization, and lower adherence.",clinicalRelevance:"Teach-back method: after education, ask the patient to explain the information back in their own words ('Can you show me how you use your inhaler?' or 'Can you tell me in your own words when you should call the doctor?'). If they cannot, re-teach using different words/methods and reassess. Studies show teach-back improves retention by 30–50% and reduces 30-day readmissions. RT education opportunities: inhaler technique, oxygen safety, pulmonary rehabilitation, asthma action plans, COPD self-management, smoking cessation, tracheostomy care, sleep apnea/CPAP.",signsSymptoms:"Signs of poor understanding: inability to demonstrate technique (inhaler, O2 equipment), asking the same questions repeatedly, non-adherence to medications, frequent ER visits/readmissions, incorrect medication use. Signs of low health literacy: difficulty completing forms, stating 'I forgot my glasses,' avoiding written materials, bringing family member to interpret.",assessment:"Assess health literacy: ask open-ended questions, observe ability to read and complete forms, use validated tools (REALM, TOFHLA). Assess learning readiness: physical comfort (pain, dyspnea), emotional state (anxiety, depression), motivation, cultural/language considerations. Assess baseline knowledge: what does the patient already know about their condition?",management:"Education delivery: (1) Use plain language (6th-grade reading level). (2) Limit to 3–5 key points. (3) Use visual aids, demonstrations, and handouts. (4) Teach-back after each key point. (5) Return demonstration for skills (inhaler, O2 setup, PEF). (6) Provide written materials to take home. (7) Follow up and reinforce at subsequent visits. Topics: disease process, medication purpose/technique, warning signs requiring medical attention, action plans, oxygen safety, activity recommendations.",complications:"Poor education → non-adherence → uncontrolled disease → ER visits/hospitalizations → disease progression. Barriers: low health literacy, language barriers, cognitive impairment, physical limitations (hearing, vision), cultural differences, limited time, patient/family anxiety.",clinicalPearls:["Teach-back is the GOLD STANDARD for assessing patient understanding — use it at every education encounter","Limit education to 3–5 key points per session — information overload reduces retention","Low health literacy is NOT related to intelligence — it affects 36% of US adults across all demographics","Assess inhaler technique at EVERY visit — 50–80% of patients use inhalers incorrectly"],examPitfalls:["Providing excessive information in a single session — limits retention","Not using teach-back to verify understanding","Assuming patients with higher education have high health literacy","Not reassessing inhaler technique at follow-up visits"],faqJson:[{question:"What is the teach-back method?",answer:"After providing education, ask the patient to explain the information back in their own words or demonstrate the skill. For example: 'I want to make sure I explained this clearly. Can you tell me in your own words when you should use your rescue inhaler?' If they cannot, re-teach and reassess. This confirms actual understanding rather than simple acknowledgment."},{question:"Why is health literacy important in respiratory education?",answer:"36% of US adults have low health literacy. These patients have 50% higher risk of hospitalization, worse disease management, lower medication adherence, and poorer health outcomes. Tailoring education to the patient's literacy level (plain language, visual aids, demonstrations) significantly improves comprehension and self-management."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"respiratory-medications-delivery",title:"Aerosol Drug Delivery Systems",category:"Pharmacology",seoTitle:"Aerosol Delivery – SVN, MDI, DPI & Mesh Nebulizers | RRT",seoDescription:"Compare aerosol delivery systems: SVN, MDI, DPI, mesh nebulizers, particle size, and clinical selection for the RRT exam.",seoKeywords:["aerosol delivery","SVN","small volume nebulizer","MDI","DPI","mesh nebulizer","aerosol therapy","RRT exam"],overview:"Aerosol drug delivery is a cornerstone of respiratory therapy. Understanding device selection, particle size, and factors affecting drug deposition is essential. Main devices: small-volume nebulizer (SVN), metered-dose inhaler (MDI ± spacer), dry powder inhaler (DPI), and vibrating mesh nebulizer. Optimal drug deposition occurs with particles 1–5 μm (respirable fraction). Device selection depends on patient capability, clinical setting, drug formulation, and cost.",mechanismPhysiology:"Aerosol deposition mechanisms: (1) Inertial impaction — large particles (> 5 μm) impact in upper airways at bifurcations (increased with fast inhalation). (2) Sedimentation — particles 1–5 μm settle by gravity in lower airways (increased with slow inhalation and breath-hold). (3) Diffusion — very small particles (< 0.5 μm) undergo Brownian motion in alveoli (may be exhaled — minimal deposition). Optimal particle size: 1–5 μm mass median aerodynamic diameter (MMAD) — reaches lower airways. Factors reducing deposition: fast inhalation (impaction), no breath-hold (less sedimentation), mouth breathing with nasal mask, poor technique.",clinicalRelevance:"SVN: gas-powered (6–8 L/min), generates continuous aerosol, easy to use (tidal breathing), 10–15% lung deposition, treatment time 10–15 minutes. Good for: acute exacerbations, patients who cannot coordinate MDI, continuous aerosol delivery. MDI + spacer: propellant-driven, 15–20% lung deposition with spacer, portable, fast (30 seconds), requires coordination (without spacer). DPI: breath-actuated (no coordination needed), requires adequate inspiratory flow (> 30–60 L/min — cannot be used in severe dyspnea, young children), 20–30% lung deposition, no propellant. Mesh nebulizer: vibrating mesh generates aerosol (no gas flow needed), quiet, efficient (> 50% lung deposition), compact, expensive.",signsSymptoms:"Device selection considerations: acute severe exacerbation → SVN (does not require coordination or high inspiratory flow). Stable outpatient → MDI + spacer or DPI (portable, fast). ICU/ventilated patient → MDI + spacer in-line or vibrating mesh nebulizer in-line. Young children (< 5 years) → SVN or MDI + spacer with mask. Severe dyspnea → SVN (DPI requires inspiratory effort that may not be achievable).",assessment:"Assess: patient's inspiratory flow capability (DPI needs > 30 L/min), coordination (MDI without spacer needs hand-breath coordination), cognitive function, clinical acuity, age. In-line (ventilated patients): MDI + spacer placed in inspiratory limb 6 inches from Y-connector, or vibrating mesh nebulizer. Assess drug delivery: clinical response (wheeze improvement, FEV1 change, SpO2), adverse effects (tachycardia, tremor).",management:"SVN: fill volume 3–5 mL (less waste with larger fill volume), flow 6–8 L/min, nebulize until sputter. MDI: shake, prime if needed, slow deep breath, actuate at start of inspiration, hold breath 10 seconds, 30–60 seconds between puffs. DPI: load dose, exhale away from device (do NOT exhale into DPI — moisture deactivates powder), inhale quickly and deeply, hold breath 10 seconds. Ventilated patients: remove HME during treatment (blocks aerosol), use heated wire circuits (reduce condensation that traps aerosol).",complications:"SVN: bronchospasm (cold aerosol), infection (if not cleaned properly), medication side effects. MDI: oropharyngeal candidiasis (ICS without spacer), poor technique reducing efficacy. DPI: inadequate drug delivery if inspiratory flow insufficient, moisture inactivation of powder.",clinicalPearls:["MDI + spacer is equivalent to SVN for bronchodilator delivery in most clinical settings","Remove the HME during aerosol treatment in ventilated patients — it acts as a filter and blocks drug delivery","DPI requires FAST deep inhalation (opposite of MDI which requires SLOW deep inhalation)","Fill volume of 3–5 mL in SVN reduces dead volume waste and improves drug delivery"],examPitfalls:["Thinking SVN is always superior to MDI — with proper technique, MDI + spacer is equivalent","Not removing the HME during in-line aerosol treatment — blocks drug delivery","Using a DPI in a patient with severe dyspnea — they cannot generate adequate inspiratory flow","Confusing MDI technique (slow deep breath) with DPI technique (fast deep breath)"],faqJson:[{question:"Why is a spacer recommended with an MDI?",answer:"A spacer: (1) slows the aerosol plume, reducing oropharyngeal impaction, (2) allows large particles to fall out (rain out), (3) eliminates the need for hand-breath coordination (the drug stays suspended in the spacer for 3–5 seconds), (4) increases lung deposition from ~10% to ~20%. Especially important with ICS to reduce oropharyngeal candidiasis."},{question:"Why must the HME be removed during aerosol treatment on a ventilator?",answer:"The heat and moisture exchanger (HME) acts as a filter that captures aerosol particles, dramatically reducing drug delivery to the patient. Remove the HME and use the heated wire humidification circuit during aerosol treatments. Replace the HME after the treatment is complete."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"diaphragm-dysfunction",title:"Diaphragm Dysfunction & Assessment",category:"Patient Assessment",seoTitle:"Diaphragm Dysfunction – Ultrasound, VIDD & Phrenic Nerve | RRT",seoDescription:"Learn diaphragm dysfunction: ventilator-induced diaphragm dysfunction, phrenic nerve injury, ultrasound assessment, and management for the RRT exam.",seoKeywords:["diaphragm dysfunction","VIDD","phrenic nerve","diaphragm ultrasound","diaphragm thickening","weaning failure","RRT exam"],overview:"Diaphragm dysfunction is an underrecognized cause of weaning failure, prolonged ventilation, and respiratory insufficiency. Ventilator-induced diaphragm dysfunction (VIDD) occurs in up to 60% of mechanically ventilated patients within 24–48 hours. Other causes include phrenic nerve injury (cardiac surgery, cervical spine injury), critical illness polyneuropathy, and neuromuscular diseases. Diaphragm ultrasound is an emerging bedside assessment tool.",mechanismPhysiology:"VIDD: controlled mechanical ventilation (CMV) removes the stimulus for diaphragmatic contraction → disuse atrophy begins within 12–18 hours of full ventilatory support. Diaphragm muscle fiber atrophy (up to 50% loss of force-generating capacity within 3 days), oxidative stress, and proteolytic pathway activation contribute. Contributing factors: over-assistance (ventilator does all the work), excessive sedation, prolonged ventilation. Protective: maintaining some diaphragmatic activity (PSV, spontaneous breathing trials) slows VIDD progression. Phrenic nerve injury: C3-C5 nerve damage → unilateral or bilateral diaphragm paralysis.",clinicalRelevance:"VIDD is the most common cause of diaphragmatic weakness in ICU patients. It prolongs weaning, increases tracheostomy rates, and worsens outcomes. Prevention: avoid full ventilatory support when possible, use PSV or modes that require patient effort, perform daily spontaneous breathing trials, target light sedation (ABCDEF bundle). Diaphragm ultrasound: bedside tool measuring diaphragm thickness and thickening fraction (TF). TF > 30% during inspiration suggests adequate diaphragm function. TF < 20% suggests dysfunction and predicts weaning failure.",signsSymptoms:"Diaphragm dysfunction signs: paradoxical abdominal movement (abdomen moves inward during inspiration — should move outward), orthopnea (worsened when supine — diaphragm cannot oppose abdominal contents), unexplained weaning failure (pass SBT criteria but fail repeatedly), reduced MIP (less than −20 cmH2O), elevated hemidiaphragm on CXR (unilateral paralysis), reduced SNIP (sniff nasal inspiratory pressure).",assessment:"Bedside: observe breathing pattern (paradoxical breathing), MIP measurement (< −20 cmH2O suggests weakness), SNIP (< −70 cmH2O is normal). Diaphragm ultrasound: measure thickness in zone of apposition (normal 1.5–2.5 mm at end-expiration), calculate thickening fraction = (thickness at end-inspiration − thickness at end-expiration) / thickness at end-expiration × 100%. TF > 30% = normal, < 20% = dysfunction. CXR: elevated hemidiaphragm suggests unilateral paralysis (fluoroscopy or sniff test confirms).",management:"Prevention (most important): avoid prolonged full ventilatory support, maintain diaphragmatic activity (partial support modes), early SBTs, minimize sedation, early mobilization. Treatment: inspiratory muscle training (IMT — breathing through threshold resistive device), optimize nutrition (protein for muscle recovery), treat underlying cause (nerve recovery after cardiac surgery — 6–12 months), phrenic nerve pacing (investigational), diaphragm plication for persistent unilateral paralysis.",complications:"Prolonged mechanical ventilation, failed weaning/extubation, tracheostomy, respiratory failure requiring readmission, reduced exercise tolerance, prolonged ICU/hospital stay.",clinicalPearls:["VIDD begins within 12–18 HOURS of controlled mechanical ventilation — it develops RAPIDLY","Diaphragm thickening fraction < 20% on ultrasound predicts weaning failure","Paradoxical abdominal breathing (inward movement during inspiration) is the clinical hallmark of diaphragm dysfunction","Maintaining some diaphragmatic activity (PSV, spontaneous modes) PROTECTS against VIDD"],examPitfalls:["Not recognizing VIDD as a cause of weaning failure","Thinking prolonged controlled ventilation is 'resting' the diaphragm — it causes atrophy","Not assessing MIP in patients with unexplained weaning failure","Not knowing that diaphragm ultrasound can assess diaphragm function at the bedside"],faqJson:[{question:"What is ventilator-induced diaphragm dysfunction?",answer:"VIDD is atrophy and weakness of the diaphragm caused by mechanical ventilation, particularly controlled modes that eliminate the need for patient effort. It begins within 12–18 hours and can reduce diaphragm force by 50% within 3 days. Prevention: maintain diaphragmatic activity through partial support modes and early SBTs."},{question:"How is diaphragm ultrasound used to assess function?",answer:"Measure diaphragm thickness at end-expiration and end-inspiration in the zone of apposition (8th-10th intercostal space, mid-axillary line). Calculate thickening fraction (TF). TF > 30% = normal contractile function. TF < 20% = diaphragm dysfunction (predicts weaning failure). It is a bedside, non-invasive, repeatable assessment."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"smoking-cessation-counseling",title:"Smoking Cessation Counseling for RTs",category:"Pulmonary Rehabilitation",seoTitle:"Smoking Cessation – 5 A's, NRT & Pharmacotherapy | RRT",seoDescription:"Learn smoking cessation: 5 A's framework, NRT options, varenicline, bupropion, motivational interviewing, and RT role for the RRT exam.",seoKeywords:["smoking cessation","5 A's","NRT","nicotine replacement","varenicline","motivational interviewing","RRT exam"],overview:"Smoking cessation is the single most effective intervention for improving respiratory health outcomes. It is the only intervention proven to slow the decline of FEV1 in COPD. Respiratory therapists are uniquely positioned to provide cessation counseling during every patient encounter. The 5 A's framework (Ask, Advise, Assess, Assist, Arrange) provides a structured approach. Combination therapy (behavioral counseling + pharmacotherapy) doubles quit rates.",mechanismPhysiology:"Nicotine addiction: nicotine binds α4β2 nicotinic ACh receptors in the VTA → dopamine release in the nucleus accumbens → reward pathway activation → dependence. Withdrawal symptoms peak at 24–72 hours: irritability, anxiety, difficulty concentrating, increased appetite, cravings. Tolerance develops rapidly — escalating doses needed for same effect. Lung effects of smoking: accelerated FEV1 decline (60 mL/year vs 25 mL/year in non-smokers), increased oxidative stress, impaired mucociliary clearance, airway inflammation, increased infection risk, increased cancer risk.",clinicalRelevance:"5 A's: (1) Ask about tobacco use at every visit. (2) Advise to quit in a clear, personalized manner. (3) Assess willingness to quit. (4) Assist with quit plan (pharmacotherapy + behavioral support). (5) Arrange follow-up within 1 week of quit date. Pharmacotherapy: NRT (patch, gum, lozenge, inhaler, nasal spray — all double quit rates), varenicline (most effective single agent — triples quit rates), bupropion (doubles quit rates, helps with weight gain/depression). Combination NRT (patch + short-acting) is more effective than single NRT.",signsSymptoms:"Readiness to quit stages (Transtheoretical model): Precontemplation (not thinking about quitting), Contemplation (considering in next 6 months), Preparation (planning to quit in next 30 days), Action (quit within last 6 months), Maintenance (quit > 6 months). Use motivational interviewing for patients not yet ready to quit — express empathy, develop discrepancy, roll with resistance, support self-efficacy.",assessment:"Assess: smoking status (current, former, never), pack-years (packs/day × years), Fagerström Test for Nicotine Dependence (FTND — score guides NRT dosing), readiness to quit (stage of change), previous quit attempts (what worked/didn't), triggers, comorbid conditions. Pack-year calculation: 1 pack/day × 20 years = 20 pack-years.",management:"Behavioral: brief counseling (even 3 minutes increases quit rates by 30%), quitline referral (1-800-QUIT-NOW), support groups, cognitive behavioral strategies, identify triggers. Pharmacotherapy: NRT patch (21 mg → 14 mg → 7 mg over 8–12 weeks) + short-acting NRT (gum/lozenge/inhaler PRN for cravings). Varenicline: 0.5 mg × 3 days → 0.5 mg BID × 4 days → 1 mg BID × 12 weeks (most effective). Bupropion: 150 mg daily × 3 days then 150 mg BID (start 1 week before quit date). E-cigarettes: NOT FDA-approved for cessation, unknown long-term safety.",complications:"Relapse (70–80% relapse within 6 months — expected, not failure), weight gain (average 4–5 kg), withdrawal symptoms, medication side effects (NRT: skin irritation, insomnia; varenicline: nausea, vivid dreams; bupropion: dry mouth, insomnia, seizure risk).",clinicalPearls:["Smoking cessation is the ONLY intervention proven to slow FEV1 decline in COPD — more effective than any medication","Even brief counseling (3 minutes) increases quit rates by 30% — EVERY RT encounter is an opportunity","Combination NRT (patch + short-acting) is more effective than single NRT","Relapse is EXPECTED, not failure — encourage patients to try again; most successful quitters make 6–7 attempts"],examPitfalls:["Not asking about smoking status at every encounter (the first 'A')","Not offering pharmacotherapy — behavioral counseling alone has lower success rates","Telling patients e-cigarettes are an FDA-approved cessation method — they are NOT","Viewing relapse as failure rather than a normal part of the cessation process"],faqJson:[{question:"What is the most effective smoking cessation pharmacotherapy?",answer:"Varenicline (Chantix) is the most effective single agent, tripling quit rates compared to placebo. Combination NRT (long-acting patch + short-acting gum/lozenge for breakthrough cravings) is similarly effective. The most effective overall strategy combines pharmacotherapy with behavioral counseling."},{question:"What are the 5 A's of smoking cessation?",answer:"Ask about tobacco use, Advise to quit (clear, personalized), Assess willingness to quit, Assist with a quit plan (pharmacotherapy + counseling), Arrange follow-up within 1 week. This structured framework ensures consistent cessation counseling at every clinical encounter."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"cystic-fibrosis-respiratory",title:"Cystic Fibrosis Respiratory Management",category:"Neonatal/Pediatric Respiratory Care",seoTitle:"Cystic Fibrosis – Airway Clearance & Respiratory Management | RRT",seoDescription:"Learn cystic fibrosis respiratory management: airway clearance, dornase alfa, hypertonic saline, CFTR modulators, and lung transplant criteria for the RRT exam.",seoKeywords:["cystic fibrosis","CF","airway clearance","dornase alfa","hypertonic saline","CFTR modulators","RRT exam"],overview:"Cystic fibrosis (CF) is an autosomal recessive disease caused by mutations in the CFTR (cystic fibrosis transmembrane conductance regulator) gene. Defective chloride transport leads to thick, dehydrated mucus in the airways, causing progressive bronchiectasis, recurrent infections, and respiratory failure. RT management focuses on airway clearance, mucolytic therapy, bronchodilators, and monitoring lung function. CF is the most common lethal genetic disease in Caucasians.",mechanismPhysiology:"CFTR protein normally functions as a chloride channel on epithelial cell surfaces. Mutations (most common: F508del) → absent or dysfunctional chloride secretion → sodium and water hyperabsorption → dehydrated, viscous airway surface liquid → impaired mucociliary clearance → mucus plugging → chronic bacterial infection (Pseudomonas aeruginosa, Staphylococcus aureus) → chronic neutrophilic inflammation → progressive bronchiectasis → respiratory failure. GI effects: pancreatic insufficiency (90%), meconium ileus, CF-related diabetes, liver disease.",clinicalRelevance:"Respiratory management pillars: (1) Airway clearance therapy — daily, multiple techniques (PEP/OPEP, CPT, HFCWO). (2) Dornase alfa (Pulmozyme) — recombinant DNase that cleaves extracellular DNA in sputum, reducing viscosity. (3) Hypertonic saline (7%) — osmotic agent that hydrates airway surface liquid and improves mucociliary clearance. (4) Bronchodilators — pre-treatment before airway clearance. (5) Inhaled antibiotics — tobramycin, aztreonam lysine (chronic Pseudomonas suppression). CFTR modulators (Trikafta: elexacaftor/tezacaftor/ivacaftor) — revolutionary therapy that corrects the underlying protein defect, dramatically improving lung function.",signsSymptoms:"Chronic productive cough (hallmark), recurrent pulmonary infections, progressive dyspnea, digital clubbing, barrel chest, hemoptysis (bronchial artery erosion), nasal polyps, failure to thrive, steatorrhea (pancreatic insufficiency), CF-related diabetes.",assessment:"Spirometry at every clinic visit: FEV1 trend is the primary lung function marker. Sputum culture q3 months (monitor bacterial colonization — Pseudomonas, MRSA). CXR/CT: bronchiectasis, mucus plugging, hyperinflation. Sweat chloride test: diagnostic (> 60 mmol/L = CF, 30–59 = intermediate, < 30 = normal). Newborn screening identifies most cases currently.",management:"Daily airway clearance: PEP/OPEP devices, CPT with postural drainage, HFCWO vest — at least twice daily. Treatment order: (1) bronchodilator, (2) hypertonic saline 7%, (3) airway clearance, (4) dornase alfa (can be given before or after ACT — timing varies by practice). Inhaled antibiotics: month-on/month-off tobramycin, or continuous aztreonam alternating with tobramycin. CFTR modulators: Trikafta for patients ≥ 2 years with at least one F508del mutation — improves FEV1 by 10–14 percentage points. Lung transplant: when FEV1 < 30% predicted with rapid decline.",complications:"Massive hemoptysis (bronchial artery embolization), pneumothorax, ABPA (allergic bronchopulmonary aspergillosis), CF-related diabetes, respiratory failure, transplant need.",clinicalPearls:["CFTR modulators (Trikafta) are revolutionizing CF care — improving FEV1, BMI, and reducing exacerbations dramatically","Treatment ORDER matters: bronchodilator → hypertonic saline → airway clearance → dornase alfa (or dornase before ACT per protocol)","Chronic Pseudomonas colonization is associated with accelerated FEV1 decline — treat aggressively","Airway clearance must be performed AT LEAST twice daily — it is the foundation of CF respiratory care"],examPitfalls:["Not knowing the correct order of CF respiratory treatments","Forgetting that dornase alfa works by breaking down DNA (not mucus glycoproteins)","Not recognizing that hypertonic saline and dornase alfa have different mechanisms — both are needed","Failing to monitor sputum cultures for Pseudomonas colonization"],faqJson:[{question:"How does dornase alfa work?",answer:"Dornase alfa (Pulmozyme) is recombinant human DNase. Neutrophils in CF airways release large amounts of DNA when they die, making sputum extremely viscous. Dornase alfa breaks down this extracellular DNA, reducing sputum viscosity and improving airway clearance. It does NOT break down mucin glycoproteins."},{question:"What is Trikafta and why is it revolutionary?",answer:"Trikafta (elexacaftor/tezacaftor/ivacaftor) is a triple-combination CFTR modulator that corrects the underlying protein defect in CF. It improves FEV1 by 10–14%, reduces pulmonary exacerbations by 63%, and improves BMI. It is effective for ~90% of CF patients (those with at least one F508del mutation)."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"acid-base-electrolyte-relationship",title:"Acid-Base & Electrolyte Relationships",category:"ABG Interpretation",seoTitle:"Acid-Base & Electrolytes – Potassium, Calcium & pH | RRT",seoDescription:"Learn acid-base electrolyte relationships: potassium-pH, calcium-pH, chloride shifts, and clinical management for the RRT exam.",seoKeywords:["acid base electrolytes","potassium pH","calcium pH","hypokalemia alkalosis","chloride shift","RRT exam"],overview:"Understanding the relationships between acid-base status and electrolytes is essential for comprehensive patient management. Key relationships: potassium and pH move in opposite directions (acidosis → hyperkalemia, alkalosis → hypokalemia), ionized calcium increases with acidosis and decreases with alkalosis, and chloride abnormalities often accompany metabolic acid-base disorders.",mechanismPhysiology:"Potassium-pH: in acidosis, excess H+ enters cells in exchange for K+ → serum K+ rises (~0.6 mEq/L per 0.1 pH decrease). In alkalosis, H+ leaves cells and K+ enters → serum K+ falls. This is clinically significant: correcting acidosis without monitoring K+ can cause dangerous hypokalemia. Calcium-pH: albumin-bound calcium increases with acidosis (H+ displaces Ca2+ from albumin) → more free ionized Ca2+. In alkalosis: more Ca2+ binds albumin → decreased ionized Ca2+ → potential tetany, paresthesias. Chloride: in metabolic alkalosis, Cl− loss (vomiting, diuretics) → kidneys retain HCO3 to maintain electroneutrality → 'chloride-responsive' alkalosis (corrected by NS infusion).",clinicalRelevance:"DKA management: initial serum K+ may be normal or high (acidosis shifts K+ out of cells), but TOTAL BODY K+ is depleted. As insulin and fluids correct the acidosis, K+ shifts back into cells → severe hypokalemia → cardiac arrhythmias. Therefore: replace K+ aggressively during DKA treatment, do NOT give insulin if K+ < 3.3. Hyperventilation/respiratory alkalosis: decreased ionized Ca2+ → perioral numbness, carpopedal spasm, Chvostek/Trousseau signs. Metabolic alkalosis: classify as chloride-responsive (urine Cl− < 20) or chloride-resistant (urine Cl− > 20).",signsSymptoms:"Hypokalemia (alkalosis-related): muscle weakness, cardiac arrhythmias (U waves, flattened T waves), ileus, respiratory muscle weakness. Hypocalcemia (alkalosis-related): paresthesias, Chvostek sign (facial twitch with tapping), Trousseau sign (carpopedal spasm with BP cuff), laryngospasm, seizures. Hyperkalemia (acidosis-related): peaked T waves, widened QRS, cardiac arrest.",assessment:"Always check electrolytes (BMP) with ABG. Calculate corrected calcium if albumin is low. Monitor ECG for potassium-related changes. In DKA: trend K+ q1–2h during treatment. In alkalosis: check ionized calcium if symptoms of hypocalcemia. Urine chloride: distinguishes chloride-responsive from chloride-resistant metabolic alkalosis.",management:"DKA: replace K+ when < 5.3 mEq/L, do NOT give insulin if < 3.3. Alkalosis with hypokalemia: correct both simultaneously — KCl replaces both K+ and Cl−. Respiratory alkalosis with tetany symptoms: reassure and guide slow breathing (for hyperventilation), treat underlying cause. Chloride-responsive metabolic alkalosis: 0.9% NS infusion (provides Cl− for renal HCO3 excretion). Chloride-resistant: treat underlying cause (hyperaldosteronism, Cushing's).",complications:"Fatal cardiac arrhythmias from hypokalemia or hyperkalemia, laryngospasm from hypocalcemia, refractory metabolic alkalosis without chloride correction.",clinicalPearls:["In DKA: serum K+ may be NORMAL initially despite severe total body depletion — K+ drops rapidly as acidosis is corrected","DO NOT give insulin in DKA if K+ < 3.3 — risk of fatal hypokalemia","Alkalosis decreases ionized Ca2+ — hyperventilation causes tetany through this mechanism","For every 0.1 decrease in pH, serum K+ rises approximately 0.6 mEq/L"],examPitfalls:["Giving insulin in DKA without checking potassium first","Not anticipating K+ drop during acidosis correction","Not recognizing that tetany during hyperventilation is from decreased ionized Ca2+ (not respiratory alkalosis directly)","Treating metabolic alkalosis without assessing chloride status (responsive vs resistant)"],faqJson:[{question:"Why does potassium rise in acidosis?",answer:"In acidosis, excess H+ ions enter cells via the H+/K+ ATPase and other exchangers. To maintain electroneutrality, K+ moves OUT of cells into the serum. This raises serum K+ by approximately 0.6 mEq/L for each 0.1 decrease in pH. Important: total body K+ may actually be depleted despite high serum K+."},{question:"Why is potassium dangerous in DKA treatment?",answer:"DKA patients are total-body K+ depleted (from osmotic diuresis) but may have normal or high serum K+ (acidosis pushes K+ out of cells). As insulin, fluids, and acidosis correction push K+ back into cells, serum K+ drops rapidly — potentially to fatal levels. Replace K+ aggressively and monitor q1–2h."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"cpap-titration-compliance",title:"CPAP Titration & Compliance Management",category:"Sleep Medicine",seoTitle:"CPAP Titration – Pressure Settings & Compliance Strategies | RRT",seoDescription:"Learn CPAP titration: in-lab vs auto-titration, compliance monitoring, mask selection, troubleshooting, and adherence strategies for the RRT exam.",seoKeywords:["CPAP titration","CPAP compliance","auto-CPAP","mask fitting","adherence","desensitization","RRT exam"],overview:"CPAP titration determines the optimal pressure to eliminate obstructive events, and compliance management ensures patients use the device consistently. CPAP adherence is the biggest challenge in OSA treatment — only 50–60% of patients meet the 4 hours/night, 70% of nights compliance definition. Respiratory therapists play a central role in mask fitting, education, troubleshooting, and compliance coaching.",mechanismPhysiology:"CPAP mechanism: continuous positive pressure pneumatically splints the upper airway open, preventing collapse during sleep. The pressure needed varies by individual (typically 4–20 cmH2O) based on anatomy, sleep position, and sleep stage (higher pressures often needed in REM/supine). Titration methods: (1) In-lab PSG titration — gold standard (RT adjusts pressure during PSG to eliminate events). (2) Auto-titrating CPAP (APAP) — device automatically adjusts pressure based on flow limitation, snoring, and apnea detection (range typically 4–20 cmH2O). (3) Empiric pressure based on prediction formulas.",clinicalRelevance:"In-lab titration protocol: start at 4 cmH2O, increase by 1 cmH2O at ≥ 5-minute intervals to eliminate apneas, then hypopneas, then snoring, then flow limitation. Optimal pressure: eliminates all events in all positions and sleep stages. APAP: appropriate for uncomplicated OSA (no CHF, COPD, central apneas, hypoventilation syndromes). Medicare compliance definition: ≥ 4 hours/night for ≥ 70% of nights during a consecutive 30-day period within the first 90 days. Non-compliance: most common reason is mask discomfort.",signsSymptoms:"Non-compliance indicators: machine data showing < 4 hours average use, persistent EDS despite CPAP prescription, patient reports removing mask at night, mask marks inconsistent with regular use. Compliance barriers: mask discomfort, claustrophobia, nasal congestion/dryness, aerophagia, pressure intolerance (difficulty exhaling against pressure), noise, lack of perceived benefit, partner complaints.",assessment:"Download CPAP data: usage hours (compliance metric), AHI on therapy (should be < 5), leak rate (high leak suggests poor mask fit), pressure data (adequate range?). Assess: mask fit and condition (replace every 3–6 months), humidifier settings, comfort features (EPR/C-Flex — pressure relief during exhalation), nasal symptoms, skin irritation. Patient interview: subjective benefit, barriers to use, sleep quality.",management:"Mask selection: nasal mask (most popular, least leak), nasal pillows (minimal contact, good for claustrophobia), full-face mask (mouth breathers, higher pressures). Trial multiple masks before prescribing. Troubleshooting: dry nose/mouth → heated humidification + chinstrap (if mouth breathing). Aerophagia → reduce pressure, consider APAP, positional therapy. Claustrophobia → desensitization protocol (wear mask during day while awake, gradually increase time). Pressure intolerance → EPR/C-Flex (reduces expiratory pressure by 1–3 cmH2O), ramp feature (starts at lower pressure and increases), APAP. Follow-up: 1 week, 1 month, 3 months, then q6–12 months.",complications:"Skin breakdown (mask contact pressure), nasal dryness/congestion, epistaxis, aerophagia, conjunctivitis (air leak toward eyes), claustrophobia, pneumothorax (extremely rare), treatment failure from non-adherence.",clinicalPearls:["Mask comfort is the #1 predictor of CPAP compliance — trial multiple masks before finalizing","Heated humidification reduces nasal dryness and congestion — improves adherence significantly","EPR/C-Flex reduces expiratory pressure by 1–3 cmH2O — helps patients who struggle against pressure during exhalation","The first 1–2 weeks are CRITICAL for establishing long-term compliance — intensive support during this period"],examPitfalls:["Not knowing Medicare's compliance definition (≥ 4 hours, ≥ 70% of nights, 30-day period)","Prescribing only one mask without offering alternatives","Not using heated humidification — most common addressable cause of nasal complaints","Not checking downloaded data for leak, AHI, and usage patterns"],faqJson:[{question:"What is the Medicare CPAP compliance definition?",answer:"The patient must use CPAP ≥ 4 hours per night for ≥ 70% of nights during a consecutive 30-day period within the first 90 days of use. If this criterion is not met, Medicare may discontinue coverage of the CPAP equipment."},{question:"What is EPR/C-Flex?",answer:"Expiratory Pressure Relief (EPR in ResMed, C-Flex in Philips) reduces the delivered pressure by 1–3 cmH2O during exhalation only. This makes exhaling against the CPAP pressure more comfortable without reducing therapeutic pressure during inspiration. It significantly improves patient comfort and compliance."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"mechanical-insufflation-exsufflation",title:"Mechanical Insufflation-Exsufflation (Cough Assist)",category:"Airway Management",seoTitle:"Mechanical Insufflation-Exsufflation – Cough Assist Device | RRT",seoDescription:"Learn mechanical insufflation-exsufflation: indications, settings, technique for neuromuscular disease, and airway clearance for the RRT exam.",seoKeywords:["mechanical insufflation exsufflation","cough assist","MIE","neuromuscular disease","peak cough flow","secretion management","RRT exam"],overview:"Mechanical insufflation-exsufflation (MIE), commonly known as Cough Assist, is a device that simulates a cough by delivering a positive pressure insufflation followed by an abrupt switch to negative pressure exsufflation. It is the primary airway clearance device for patients with neuromuscular disease (ALS, SMA, muscular dystrophies, spinal cord injury) who have inadequate cough strength due to respiratory muscle weakness.",mechanismPhysiology:"The device delivers a positive pressure breath (+30 to +40 cmH2O) to maximally inflate the lungs, then rapidly switches to negative pressure (−30 to −40 cmH2O) to simulate the expulsive phase of a cough. The rapid pressure swing generates high expiratory flow rates (similar to a natural cough), mobilizing secretions from peripheral to central airways. Normal cough requires peak cough flow (PCF) > 160 L/min to clear secretions effectively. Neuromuscular patients often have PCF < 160 L/min, making natural cough inadequate.",clinicalRelevance:"Indications: any condition causing respiratory muscle weakness with impaired cough — ALS, SMA (Type I-III), Duchenne muscular dystrophy, myasthenic crisis, high spinal cord injury (C1-C5), post-polio syndrome. When to start: PCF < 270 L/min (start training), PCF < 160 L/min (essential for secretion clearance). MIE reduces the need for suctioning, prevents mucus plugging and atelectasis, and reduces respiratory infections. It can be used via mask, mouthpiece, or tracheostomy.",signsSymptoms:"Indications for MIE use: weak cough, recurrent respiratory infections, difficulty clearing secretions, declining FVC (< 50% predicted in NMD), peak cough flow < 270 L/min, SpO2 drops with respiratory infections. Effectiveness indicators: audible secretion clearance, improved SpO2 after treatment, reduced need for suctioning.",assessment:"Assess: PCF (peak cough flow meter), FVC (spirometry — < 50% suggests need for MIE evaluation), cough strength (manual assessment), secretion burden, SpO2 baseline and with infections. Monitor during treatment: SpO2, HR, patient tolerance, secretion clearance. Effectiveness: improved SpO2, audible secretion movement, reduced respiratory distress after treatment.",management:"Settings: insufflation +30 to +40 cmH2O, exsufflation −30 to −40 cmH2O (pressures should be symmetric or slightly higher exsufflation). Insufflation time: 2–3 seconds. Exsufflation time: 2–3 seconds. Pause: 1–2 seconds. Protocol: 5 cycles of insufflation-exsufflation, then pause for normal breathing, repeat 4–5 sets. Apply abdominal thrust simultaneously with exsufflation for maximum effect. Frequency: 2–4 times daily routinely, q2–4h during respiratory infections.",complications:"Gastric distension (especially with mask interface — place NG if significant), hemodynamic effects (rare — transient BP/HR changes), pneumothorax (extremely rare, avoid in patients with known bullae), discomfort/gagging, barotrauma (avoid in untreated pneumothorax).",clinicalPearls:["MIE is the CORNERSTONE of airway clearance in neuromuscular disease — more effective than suctioning","Apply simultaneous abdominal thrust during exsufflation phase for maximum cough flow generation","PCF < 160 L/min = inadequate natural cough — MIE is essential","MIE can be used via mask, mouthpiece, OR tracheostomy — versatile for all interfaces"],examPitfalls:["Not recommending MIE for neuromuscular patients with weak cough","Setting insufflation and exsufflation pressures too low (< 30 cmH2O) — inadequate for effective clearance","Not coordinating abdominal thrust with the exsufflation phase","Using MIE in patients with untreated pneumothorax or significant bullous disease"],faqJson:[{question:"How does MIE simulate a cough?",answer:"MIE delivers a positive pressure breath (+30 to +40 cmH2O) to fully inflate the lungs, then rapidly switches to negative pressure (−30 to −40 cmH2O). This creates a high expiratory flow rate that simulates the explosive expiratory phase of a natural cough, moving secretions from peripheral to central airways."},{question:"When should MIE be initiated in neuromuscular disease?",answer:"Begin MIE training when peak cough flow (PCF) drops below 270 L/min. MIE becomes essential when PCF drops below 160 L/min — at this level, the patient cannot generate adequate cough force to clear secretions naturally."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"ventilator-weaning-liberation",title:"Ventilator Weaning & Liberation",category:"Mechanical Ventilation",seoTitle:"Ventilator Weaning – SBT, Readiness Criteria & Protocols | RRT",seoDescription:"Learn ventilator weaning: readiness assessment, spontaneous breathing trials, RSBI, extubation criteria, and weaning protocols for the RRT exam.",seoKeywords:["ventilator weaning","SBT","spontaneous breathing trial","RSBI","rapid shallow breathing index","extubation","liberation","RRT exam"],overview:"Ventilator weaning (liberation) is the process of transitioning patients from mechanical ventilation to spontaneous breathing. It accounts for up to 40% of total ventilator time. Protocol-driven weaning by respiratory therapists reduces ventilation duration by 25%. Key components: daily readiness assessment, spontaneous breathing trial (SBT), rapid shallow breathing index (RSBI), and extubation decision-making.",mechanismPhysiology:"Weaning success depends on the balance between respiratory load (resistance, compliance, minute ventilation demand) and respiratory capacity (respiratory muscle strength, neural drive, nutritional status). Weaning failure occurs when load exceeds capacity. RSBI = f/Vt (respiratory frequency divided by tidal volume in liters). RSBI < 105 predicts successful weaning (sensitivity 97%). SBT: period of minimal or no ventilatory support (T-piece, PSV 5–8/PEEP 5, or CPAP 5) for 30–120 minutes to assess tolerance.",clinicalRelevance:"Daily readiness screen: (1) underlying cause improved/resolving, (2) adequate oxygenation (PaO2/FiO2 > 150 on FiO2 ≤ 0.40, PEEP ≤ 8), (3) hemodynamically stable (no/low vasopressors), (4) able to initiate spontaneous breaths, (5) adequate mental status (follows commands or appropriate neurological baseline). If screen positive → proceed to SBT. SBT methods: T-piece (no ventilator support), PSV 5–8 / PEEP 5 (minimal support), automatic tube compensation (ATC — compensates for tube resistance).",signsSymptoms:"SBT failure criteria: RR > 35 for > 5 minutes, SpO2 < 90%, HR > 140 or change > 20%, SBP > 180 or < 90, agitation/anxiety/diaphoresis, paradoxical breathing. Weaning failure risk factors: COPD, heart failure, neuromuscular disease, prolonged ventilation, ICU-acquired weakness, obesity, unresolved underlying condition, inadequate nutrition.",assessment:"RSBI measurement: measure RR and Vt during 1 minute of unassisted breathing (T-piece or CPAP 0). RSBI < 105 = likely to wean (positive predictive value ~80%). RSBI > 105 = likely to fail. Other parameters: NIF/MIP (< −20 cmH2O adequate), vital capacity (> 10 mL/kg), minute ventilation (< 10 L/min). SBT observation: continuously for 30–120 minutes — HR, RR, BP, SpO2, patient effort, mental status.",management:"Protocol-driven approach: daily sedation interruption (SAT) paired with SBT (SAT/SBT bundle). Pass SBT: assess for extubation (cuff leak test if prolonged intubation or high risk for stridor, ability to protect airway, manage secretions). Fail SBT: return to previous ventilator settings, identify and treat reversible causes (fluid overload, bronchospasm, inadequate nutrition, anxiety), retry in 24 hours. Difficult weaning: gradual reduction (PSV weaning, SIMV rate reduction — PSV preferred). Prolonged weaning (> 7 days of unsuccessful trials): consider tracheostomy, specialized weaning unit.",complications:"Failed extubation (re-intubation rate 10–20% — associated with worse outcomes), post-extubation stridor (consider prophylactic steroids), aspiration, respiratory failure requiring re-intubation, prolonged ICU stay.",clinicalPearls:["RT-driven weaning protocols reduce ventilation duration by 25% — evidence is strong","RSBI < 105 is the best single predictor of weaning success (sensitivity 97%)","Pair daily SAT (sedation awakening trial) with SBT — the SAT/SBT bundle improves outcomes","Failed SBT: identify and treat the CAUSE (fluid overload, bronchospasm, weakness, anxiety) before retrying"],examPitfalls:["Not performing daily weaning readiness assessment — delays liberation","Using RSBI alone without performing an actual SBT — RSBI is a screening tool, not definitive","Not knowing SBT failure criteria (RR > 35, SpO2 < 90%, hemodynamic changes)","Forgetting to assess cuff leak and airway protection before extubation"],faqJson:[{question:"What is the rapid shallow breathing index (RSBI)?",answer:"RSBI = respiratory frequency (f) divided by tidal volume in liters (Vt). Measured during 1 minute of unassisted breathing. RSBI < 105 predicts successful weaning with 97% sensitivity. RSBI > 105 suggests the patient is breathing too rapidly and shallowly to sustain independent ventilation."},{question:"What is the SAT/SBT bundle?",answer:"Daily Sedation Awakening Trial (SAT) paired with Spontaneous Breathing Trial (SBT). First, reduce/stop sedation to assess neurological function. If the patient awakens appropriately, proceed to SBT. This paired approach has been shown to reduce ventilation duration and ICU mortality."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"arterial-line-monitoring",title:"Arterial Line Monitoring for RTs",category:"Critical Care",seoTitle:"Arterial Line – Continuous BP & ABG Sampling | RRT",seoDescription:"Learn arterial line monitoring: insertion sites, waveform interpretation, zeroing and leveling, and troubleshooting for the RRT exam.",seoKeywords:["arterial line","arterial catheter","continuous blood pressure","arterial waveform","zeroing","leveling","RRT exam"],overview:"Arterial line (A-line) monitoring provides continuous blood pressure measurement and easy access for frequent arterial blood gas sampling. It is standard in critically ill patients requiring vasoactive medications, frequent ABG monitoring, or hemodynamic instability. Respiratory therapists use arterial lines for ABG sampling and should understand waveform interpretation, zeroing/leveling, and troubleshooting.",mechanismPhysiology:"A fluid-filled catheter in the artery transmits pressure waves through tubing to a pressure transducer, which converts mechanical pressure to an electrical signal displayed as a continuous waveform. Arterial waveform: systolic upstroke (ventricular ejection), dicrotic notch (aortic valve closure — marks end of systole/beginning of diastole), diastolic runoff (declining pressure during diastole). Systolic pressure = peak of waveform. Diastolic pressure = nadir. MAP = diastolic + 1/3 × (systolic − diastolic).",clinicalRelevance:"Indications: hemodynamic instability requiring continuous BP monitoring, vasoactive drug titration (vasopressors, vasodilators), frequent ABG sampling (≥ 4/day), severe respiratory failure requiring close monitoring, intra-aortic balloon pump timing. Insertion sites: radial (preferred — modified Allen test first), femoral, dorsalis pedis, brachial, axillary. Radial advantages: collateral circulation (ulnar artery), easy access, low complication rate.",signsSymptoms:"Waveform abnormalities: overdamped (flattened waveform, loss of dicrotic notch — falsely low systolic, high diastolic) — causes: air bubble, clot, kink, soft tubing, loose connections. Underdamped (spiked waveform with artifact, falsely high systolic, low diastolic) — causes: excessive tubing length, small air bubble resonance. Absent waveform: disconnection, clot, catheter against vessel wall.",assessment:"Zeroing: open transducer to atmosphere at the phlebostatic axis (4th intercostal space, mid-axillary line) — zeroes the system to atmospheric pressure. Level: position transducer at the phlebostatic axis — if too low, reads falsely high; if too high, reads falsely low (1.36 cmH2O per cm of height difference). Re-zero: with position changes, q8–12h, when readings don't match clinical picture. Assess waveform quality: clear dicrotic notch present, appropriate systolic/diastolic values.",management:"Maintenance: continuous heparinized saline flush (3 mL/hr pressurized bag at 300 mmHg), assess insertion site q shift (infection, hematoma), assess distal perfusion (pulses, capillary refill, color, temperature). ABG sampling: waste 3–5 mL before collecting sample (clears flush solution), collect sample, flush line after sampling. Troubleshooting overdamped: flush line (fast flush test), remove air bubbles, check connections, assess for clot. Remove A-line when no longer needed — minimize indwelling time.",complications:"Infection (risk increases with duration), thrombosis, hemorrhage (disconnection — arterial bleeding is rapid and potentially fatal), distal ischemia, hematoma, nerve damage, accidental intra-arterial injection.",clinicalPearls:["Always zero and level the transducer at the phlebostatic axis — 4th ICS, mid-axillary line","The dicrotic notch should be visible on a properly damped arterial waveform — its absence suggests overdamping","Waste 3–5 mL before ABG sampling from an A-line — the dead space contains flush solution, not arterial blood","A-line disconnection = arterial hemorrhage — all connections must be secure and visible"],examPitfalls:["Not zeroing the transducer at the phlebostatic axis — gives inaccurate readings","Not recognizing overdamped vs underdamped waveforms and their effects on BP readings","Not wasting dead space blood before sampling — dilutes the ABG sample with flush solution","Leaving an A-line in place longer than needed — increases infection and thrombosis risk"],faqJson:[{question:"What is the phlebostatic axis?",answer:"The intersection of the 4th intercostal space and the mid-axillary line. This approximates the level of the right atrium. The pressure transducer must be zeroed and leveled at this point for accurate readings. If the transducer is below this level, readings are falsely HIGH; if above, falsely LOW."},{question:"What does the dicrotic notch represent?",answer:"The dicrotic notch on the arterial waveform represents aortic valve closure — the transition from systole to diastole. Its presence confirms proper waveform quality (appropriate damping). Absence of the dicrotic notch suggests overdamping (air bubble, clot, kink) and the readings may be inaccurate."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"neonatal-surfactant-administration",title:"Surfactant Administration Techniques",category:"Neonatal/Pediatric Respiratory Care",seoTitle:"Surfactant Administration – INSURE, LISA & Dosing | RRT",seoDescription:"Learn surfactant administration: INSURE technique, LISA method, dosing, indications, and complications for the RRT exam.",seoKeywords:["surfactant administration","INSURE","LISA","less invasive surfactant","neonatal RDS","surfactant replacement","RRT exam"],overview:"Exogenous surfactant replacement therapy is a life-saving treatment for neonatal respiratory distress syndrome (RDS). Modern administration techniques aim to deliver surfactant while minimizing mechanical ventilation exposure. Key methods: traditional bolus via ETT, INSURE (INtubate, SURfactant, Extubate), and LISA/MIST (Less/Minimally Invasive Surfactant Administration). The RT plays a central role in all surfactant administration techniques.",mechanismPhysiology:"Surfactant is a phospholipid-protein mixture (primarily DPPC — dipalmitoylphosphatidylcholine) produced by Type II alveolar cells. It reduces alveolar surface tension, preventing alveolar collapse at end-expiration (LaPlace's law). In preterm infants, surfactant production is insufficient → high surface tension → alveolar collapse → atelectasis → hypoxemia → RDS. Exogenous surfactant: animal-derived (beractant/Survanta, calfactant/Infasurf, poractant alfa/Curosurf) or synthetic. Replaces the deficient endogenous surfactant, improving compliance and gas exchange within minutes.",clinicalRelevance:"Traditional administration: intubate → administer surfactant in 1–4 aliquots through ETT (position changes between aliquots for distribution) → continue mechanical ventilation. INSURE: intubate → surfactant → extubate to CPAP within minutes. Advantage: reduces ventilator time and BPD risk. LISA (Less Invasive Surfactant Administration): thin catheter inserted through vocal cords while infant breathes on CPAP → surfactant instilled without intubation → catheter removed. Advantage: avoids intubation entirely, least invasive. Growing evidence favors LISA as optimal technique.",signsSymptoms:"Indications: preterm infant with clinical and radiographic RDS, FiO2 > 0.30 on CPAP (early rescue), confirmed RDS on CXR (ground glass, air bronchograms, low lung volumes). Timing: early rescue (within 2 hours of birth) preferred over late rescue or prophylactic administration. Response indicators: rapid improvement in SpO2, ability to wean FiO2 (sometimes dramatically), improved compliance (may need to reduce ventilator pressures to prevent overdistension).",assessment:"Pre-administration: confirm ETT position (for traditional/INSURE), verify weight-based dose, have monitoring in place (SpO2, HR, BP). During: monitor SpO2, HR, observe for bradycardia, desaturation, ETT obstruction. Post-administration: rapid FiO2 weaning expected — monitor closely and reduce FiO2 to avoid hyperoxia. CXR improvement within hours. May need to reduce ventilator pressures as compliance improves (avoid overdistension/pneumothorax).",management:"Dosing: poractant alfa (Curosurf) 200 mg/kg initial, then 100 mg/kg repeat (up to 2 additional doses q12h). Beractant (Survanta) 100 mg/kg × up to 4 doses q6h. Calfactant (Infasurf) 105 mg/kg × up to 3 doses q12h. Administration: warm to room temperature, gentle swirling (do NOT shake — disrupts phospholipid structure). INSURE: intubate (brief), instill surfactant, ventilate briefly, extubate to CPAP. LISA: position infant on CPAP, direct laryngoscopy, thread thin catheter past cords, instill slowly over 1–3 minutes, remove catheter.",complications:"Transient bradycardia and desaturation during administration, ETT obstruction (surfactant bolus), pneumothorax (if ventilator pressures not reduced after compliance improvement), pulmonary hemorrhage (rare), uneven distribution.",clinicalPearls:["LISA is emerging as the preferred technique — delivers surfactant without intubation, reducing BPD risk","After surfactant administration, compliance improves RAPIDLY — be ready to reduce ventilator pressures and FiO2 immediately","Do NOT shake surfactant — gentle swirling only (shaking disrupts phospholipid structure)","Poractant alfa (Curosurf) at 200 mg/kg has the best evidence for initial dosing"],examPitfalls:["Not reducing ventilator pressures after surfactant improves compliance — risk of pneumothorax","Shaking the surfactant preparation — disrupts phospholipid structure","Not monitoring for transient bradycardia and desaturation during administration","Not knowing the differences between INSURE and LISA techniques"],faqJson:[{question:"What is the LISA technique?",answer:"Less Invasive Surfactant Administration: a thin catheter is passed through the vocal cords under direct laryngoscopy while the infant breathes spontaneously on CPAP. Surfactant is slowly instilled through the catheter over 1–3 minutes. The catheter is then removed. The infant is never intubated or mechanically ventilated."},{question:"Why must ventilator settings be adjusted after surfactant?",answer:"Surfactant dramatically improves lung compliance within minutes. If ventilator pressures are not reduced, the now-compliant lungs receive excessive tidal volumes, leading to overdistension and potentially pneumothorax. FiO2 also drops rapidly — failure to wean can cause hyperoxia."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"humidity-therapy",title:"Humidity & Aerosol Therapy",category:"Oxygen Therapy",seoTitle:"Humidity Therapy – HME vs Heated Humidifier | RRT Encyclopedia",seoDescription:"Learn humidity therapy: HME, heated humidifiers, absolute vs relative humidity, and clinical applications for the RRT exam.",seoKeywords:["humidity therapy","HME","heated humidifier","absolute humidity","bland aerosol","RRT exam"],overview:"Adequate humidification of inspired gases is essential during respiratory therapy. The upper airway normally heats and humidifies inspired gas to 37°C with 100% relative humidity (44 mg/L absolute humidity) at the carina — the isothermic saturation boundary (ISB). When the upper airway is bypassed (ETT, tracheostomy) or high-flow dry gas is delivered, external humidification is required to prevent airway damage.",mechanismPhysiology:"The nose and upper airway warm inspired gas to body temperature and saturate it with water vapor. When bypassed: cold, dry gas contacts the lower airway mucosa → mucosal drying → impaired mucociliary clearance → mucus plugging → increased infection risk. Heat and moisture exchangers (HMEs): passive devices that capture exhaled heat and moisture and return it to the next inspired breath. Heated humidifiers: actively heat water to produce water vapor, delivering gas at 34–41°C with 33–44 mg/L absolute humidity. Bland aerosol: particles of water (sterile water or saline) suspended in gas — used for sputum induction or to supplement humidification.",clinicalRelevance:"HME: convenient, no power/water needed, reduced circuit condensation, lower cost. Limitations: adds dead space (30–90 mL), increases resistance, must be removed during aerosol treatments, contraindicated with thick/bloody secretions (may occlude). Heated humidifier: gold standard for long-term ventilation, high-flow nasal cannula, and patients with thick secretions. Heated wire circuits reduce condensation (rain-out). HFNC always uses heated humidification (37°C, 44 mg/L).",signsSymptoms:"Signs of inadequate humidification: thick tenacious secretions, mucus plugging, increased work of breathing, difficulty passing suction catheter, dry crackles, elevated PIP (mucus obstruction). Signs of excessive humidification: excessive condensation (rain-out), water in ventilator tubing, potential aspiration of condensate.",assessment:"Monitor: secretion consistency (should be thin and easily suctioned), HME resistance (change q24h or if occluded), humidifier temperature (target 34–37°C at airway), condensation in circuit (drain away from patient). Ensure HME is appropriate size for patient Vt (check dead space volume).",management:"Intubated patients: HME (short-term, no thick secretions) or heated humidifier (long-term, thick secretions, large air leak). HFNC: heated humidifier required (integrated into device). Tracheostomy: heated humidifier or trach collar with cool mist. HME contraindications: thick/bloody secretions, large air leak (bypasses HME), hypothermia treatment, during aerosol drug delivery. Change HME every 24 hours or when visibly soiled.",complications:"HME occlusion (secretions blocking filter), increased dead space (especially in small Vt patients), inadequate humidification (hypothermia, dehydrated mucosa), condensation aspiration, thermal injury (overheated humidifier).",clinicalPearls:["Remove the HME during nebulizer treatments — it filters out the aerosol medication","HME contraindicated with thick/bloody secretions — they occlude the filter, increasing resistance","Heated wire circuits reduce condensation rain-out — preferred for heated humidifiers","HFNC requires heated humidification at 37°C to deliver comfortable, fully conditioned gas"],examPitfalls:["Leaving an HME in place during nebulizer treatments — blocks drug delivery","Using an HME in a patient with thick secretions — risk of occlusion and increased WOB","Not knowing the isothermic saturation boundary (37°C, 44 mg/L at the carina)","Forgetting to change HMEs every 24 hours"],faqJson:[{question:"What is the isothermic saturation boundary?",answer:"The point in the airway (normally at the carina) where inspired gas reaches body temperature (37°C) and 100% relative humidity (44 mg/L absolute humidity). When the upper airway is bypassed, the ISB shifts deeper into the lungs, and external humidification must replace the conditioning normally provided by the nose and upper airway."},{question:"When should a heated humidifier be used instead of an HME?",answer:"Heated humidifier is preferred for: prolonged mechanical ventilation (> 96 hours), thick or bloody secretions, large circuit air leak (bypasses HME), patients with hypothermia, high-flow nasal cannula therapy, and during aerosol drug delivery."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"lung-compliance-resistance",title:"Lung Compliance & Resistance",category:"Patient Assessment",seoTitle:"Lung Compliance & Resistance – Static, Dynamic & Calculations | RRT",seoDescription:"Learn lung compliance and resistance: static vs dynamic compliance, airway resistance calculations, and clinical significance for the RRT exam.",seoKeywords:["lung compliance","airway resistance","static compliance","dynamic compliance","PIP","plateau pressure","RRT exam"],overview:"Understanding lung compliance (distensibility) and airway resistance is fundamental for ventilator management. Static compliance (Cst) reflects lung/chest wall elasticity, while dynamic compliance (Cdyn) includes both elastic and resistive components. Calculations using PIP, plateau pressure, and PEEP guide ventilator adjustments and diagnose clinical changes.",mechanismPhysiology:"Compliance = change in volume / change in pressure (mL/cmH2O). Normal static compliance: 60–100 mL/cmH2O (ventilated patients: 40–60). Static compliance (Cst) = Vt / (Pplat − PEEP) — reflects lung/chest wall elasticity only (no airflow). Dynamic compliance (Cdyn) = Vt / (PIP − PEEP) — includes both elastic and resistive components. Resistance = (PIP − Pplat) / flow — reflects airway resistance. Normal airway resistance: 0.5–2.5 cmH2O/L/s (higher through ET tube). Plateau pressure (Pplat) measured during inspiratory hold — reflects alveolar pressure without flow.",clinicalRelevance:"Decreased Cst (Pplat rises): atelectasis, pneumothorax, pulmonary edema, ARDS, fibrosis, chest wall restriction (obesity, ascites). Decreased Cdyn with normal Cst (PIP rises but Pplat normal): increased airway resistance — bronchospasm, secretions, mucus plug, kinked ET tube. Both decrease: combination of problems. Driving pressure = Pplat − PEEP: independent predictor of ARDS mortality (target < 15 cmH2O). Monitoring trends in compliance and resistance provides early warning of clinical changes.",signsSymptoms:"Rising PIP with stable Pplat: airway resistance problem (bronchospasm, secretions, tube kink). Rising PIP AND Pplat: compliance problem (atelectasis, edema, pneumothorax). Falling compliance trend: worsening lung disease, overdistension. Improving compliance: responding to treatment (recruitment, diuresis).",assessment:"Measurements: perform inspiratory hold to measure Pplat (patient must be passive — no spontaneous effort). Calculate: Cst = Vt / (Pplat − PEEP). Cdyn = Vt / (PIP − PEEP). Raw = (PIP − Pplat) / flow (L/s). Monitor trends: document q4h or with clinical changes. Driving pressure = Pplat − PEEP (target < 15 in ARDS).",management:"Low compliance: optimize PEEP (recruitment), treat underlying cause (drain effusion, decompress pneumothorax, diurese edema), reduce Vt if overdistension. High resistance: bronchodilators (bronchospasm), suction (secretions), reposition/replace ET tube (kink/obstruction), increase tube size if feasible. Target: Pplat < 30 cmH2O (lung-protective), driving pressure < 15.",complications:"Overdistension from excessive Vt or PEEP (worsens compliance, increases dead space), barotrauma, VILI from high driving pressures.",clinicalPearls:["PIP − Pplat difference reflects airway RESISTANCE; Pplat − PEEP reflects lung COMPLIANCE","Rising PIP with UNCHANGED Pplat = airway problem (bronchospasm, secretions, kink)","Rising PIP with RISING Pplat = lung/chest wall problem (atelectasis, edema, pneumothorax)","Driving pressure (Pplat − PEEP) < 15 cmH2O is associated with better ARDS outcomes"],examPitfalls:["Not performing inspiratory hold to measure Pplat — cannot calculate compliance without it","Confusing PIP changes with compliance changes — PIP includes resistance component","Not distinguishing airway resistance problems from compliance problems","Forgetting that the patient must be passive (not breathing) for accurate Pplat measurement"],faqJson:[{question:"How do you distinguish a resistance problem from a compliance problem?",answer:"Perform an inspiratory hold to measure Pplat. If PIP is elevated but Pplat is normal: the problem is airway resistance (bronchospasm, secretions, kinked tube). If both PIP and Pplat are elevated: the problem is lung or chest wall compliance (atelectasis, edema, pneumothorax, chest wall restriction)."},{question:"What is driving pressure and why is it important?",answer:"Driving pressure = Pplat − PEEP. It represents the pressure distending the lung above its resting volume. In ARDS, driving pressure < 15 cmH2O is independently associated with improved survival. It may be a better predictor of VILI than Pplat or Vt alone."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"chest-xray-interpretation-rt",title:"Chest X-Ray Interpretation for RTs",category:"Patient Assessment",seoTitle:"Chest X-Ray Interpretation – ET Tube Position & Lung Findings | RRT",seoDescription:"Learn chest x-ray interpretation: ET tube position, line placement, pneumothorax, pleural effusion, and common findings for the RRT exam.",seoKeywords:["chest x-ray","CXR","ET tube position","pneumothorax","pleural effusion","consolidation","RRT exam"],overview:"Chest x-ray (CXR) interpretation is an essential respiratory therapy skill. RTs are often the first to evaluate tube and line placement, identify acute changes (pneumothorax, atelectasis, new infiltrates), and correlate radiographic findings with clinical status. Systematic approach: assess technical quality (rotation, penetration, inspiration), then evaluate tubes/lines, airway, lungs, heart/mediastinum, bones, and soft tissue.",mechanismPhysiology:"X-ray physics: x-rays pass through the patient and are attenuated by different tissues to varying degrees. Air: appears black (radiolucent). Bone/metal: appears white (radiopaque). Soft tissue/fluid: appears gray. Fat: appears dark gray. Systematic approach (ABCDEFG): A (Airway — trachea midline, ET tube position), B (Bones — fractures, lytic lesions), C (Cardiac — heart size, silhouette), D (Diaphragm — level, costophrenic angles), E (Effusion/Extra-pulmonary), F (Fields — lung parenchyma), G (Gadgets — tubes, lines, devices).",clinicalRelevance:"ET tube position: tip should be 3–5 cm above the carina (approximately T3–T4 level on AP CXR). Right mainstem intubation: tip too low (below carina) — left lung atelectasis. Too high: risk of accidental extubation. Central line: tip at SVC-RA junction. NG/OG tube: tip below diaphragm in stomach. Pneumothorax: absent lung markings, visible pleural line, deep sulcus sign on supine CXR. Pleural effusion: meniscus sign, costophrenic angle blunting. Consolidation: air bronchograms within opacified lung.",signsSymptoms:"Pneumothorax on CXR: absent lung markings peripherally, visible visceral pleural line. On supine CXR (ICU): deep sulcus sign (lucent costophrenic angle), sharp hemidiaphragm outline. Pleural effusion: blunting of costophrenic angle (needs ~200 mL to be visible on upright PA). Atelectasis: volume loss (elevated hemidiaphragm, mediastinal shift TOWARD the opacity, crowded ribs). Consolidation: air bronchograms, NO volume loss, may have silhouette sign.",assessment:"Systematic evaluation: (1) Technical quality — rotation (clavicle heads equidistant from spinous processes), penetration (vertebral bodies barely visible through the heart), adequate inspiration (10 posterior ribs visible). (2) ET tube position (3–5 cm above carina). (3) All other tubes/lines. (4) Trachea (midline?). (5) Heart size (CT ratio < 0.5 on PA). (6) Both lungs systematically. (7) Costophrenic angles (effusion?). (8) Diaphragms (elevated = atelectasis, phrenic nerve injury). (9) Bones and soft tissue.",management:"ET tube repositioned if tip is not 3–5 cm above carina. Right mainstem: withdraw tube 2–3 cm, reconfirm with CXR. Pneumothorax: chest tube if symptomatic or large. Atelectasis: increase PEEP, recruitment maneuver, position changes, airway clearance. New infiltrate: correlate with clinical picture (pneumonia, aspiration, edema, ARDS). Always correlate CXR with clinical status — treat the patient, not the x-ray.",complications:"Misinterpretation leading to inappropriate interventions, missed pneumothorax (especially on supine CXR), missed right mainstem intubation, radiation exposure (minimize unnecessary CXRs).",clinicalPearls:["ET tube tip should be 3–5 cm above the carina — approximately at T3–T4 vertebral level","On supine ICU CXR, look for the DEEP SULCUS SIGN to detect pneumothorax — air rises anteriorly","Atelectasis causes volume LOSS (shift toward opacity) while consolidation does NOT","Always check that the trachea is midline — deviation suggests tension pneumothorax, effusion, or atelectasis"],examPitfalls:["Missing pneumothorax on supine CXR — it does NOT show a classic apical pleural line","Not verifying ET tube position on every post-intubation CXR","Confusing atelectasis (volume loss) with consolidation (no volume loss)","Forgetting to check ALL tubes and lines on every CXR"],faqJson:[{question:"Where should the ET tube tip be on CXR?",answer:"3–5 cm above the carina, approximately at the T3–T4 vertebral level on an AP chest x-ray. If the tip is at or below the carina, it is likely in the right mainstem bronchus (withdraw 2–3 cm). If too high above the cords, risk of accidental extubation."},{question:"How does pneumothorax appear on a supine CXR?",answer:"On supine films (common in ICU), air collects anteriorly and inferiorly rather than at the apex. Look for: deep sulcus sign (unusually lucent costophrenic angle), sharp hemidiaphragm outline, and increased lucency over the affected hemithorax. A classic apical pleural line may NOT be visible."}],relatedLessonIds:[],relatedQuestionIds:[]},

  {slug:"blood-gas-sampling-analysis",title:"ABG Sampling & Pre-Analytical Errors",category:"ABG Interpretation",seoTitle:"ABG Sampling – Technique, Errors & Quality Control | RRT",seoDescription:"Learn ABG sampling: modified Allen test, pre-analytical errors, air bubbles, temperature correction, and quality control for the RRT exam.",seoKeywords:["ABG sampling","arterial blood gas","modified Allen test","pre-analytical error","air bubble","heparin dilution","RRT exam"],overview:"Proper arterial blood gas sampling technique and understanding of pre-analytical errors are essential RT competencies. Errors in sampling, handling, or analysis can lead to incorrect ABG results and inappropriate clinical decisions. Key considerations: modified Allen test (collateral circulation assessment), proper heparin anticoagulation, air bubble elimination, sample handling (ice, timing), and recognition of common pre-analytical errors.",mechanismPhysiology:"Sampling sites (preference order): radial artery (safest — dual blood supply via ulnar artery), brachial artery (larger, deeper — greater complication risk), femoral artery (last resort — highest complication risk, may sample venous blood inadvertently). Modified Allen test: assesses ulnar collateral circulation before radial puncture — have patient clench fist, occlude both radial and ulnar arteries, release ulnar → hand should pink up within 5–10 seconds (positive test = adequate collateral). Pre-analytical errors: (1) Air bubbles — equilibrate with atmospheric PO2 (150 mmHg) and PCO2 (0.3 mmHg), falsely raising PaO2 and lowering PaCO2. (2) Excess heparin — dilutes the sample, falsely lowering PaCO2, PaO2, and HCO3. (3) Delayed analysis — cellular metabolism continues, consuming O2 (PaO2 falls) and producing CO2 (PaCO2 rises). (4) Venous admixture — falsely low PaO2, high PaCO2.",clinicalRelevance:"Air bubbles: even small bubbles significantly affect PaO2. Room air PO2 is ~150 mmHg — if patient's PaO2 is 60, the bubble raises it. Effect is greater on PaO2 than PaCO2 (room air PCO2 is near zero vs patient PCO2 of ~40). Heparin dilution: use pre-heparinized syringes with minimal dead space. Excess liquid heparin dilutes the sample and changes results. Timing: analyze within 10–30 minutes if kept at room temperature, or within 60 minutes on ice. Delay at room temperature causes PaO2 to fall (cellular O2 consumption) and PaCO2 to rise (cellular CO2 production).",signsSymptoms:"Indicators of pre-analytical error: results inconsistent with clinical picture, impossible values (PaO2 > 150 on room air), sudden large change from prior ABG without clinical change. Quality indicators: analyze promptly, minimal air exposure, proper heparin, correlate with clinical status.",assessment:"Pre-sampling: modified Allen test (radial artery), patient assessment (anticoagulation status, respiratory status, FiO2, ventilator settings). Sampling: use pre-heparinized syringe, 45° angle to radial artery, pulsatile flow confirms arterial (not venous), expel air bubbles immediately, cap syringe, roll between palms (mix with heparin). Post-sampling: apply pressure for 5 minutes (15+ minutes if anticoagulated), place sample on ice if analysis delayed > 10 minutes, document FiO2/ventilator settings, analyze within 10–30 minutes.",management:"Specimen handling: expel ALL air bubbles immediately (flick syringe, push plunger to expel). Cap syringe to prevent atmospheric gas exchange. Ice sample if delay > 10 minutes (slows cellular metabolism — reduces O2 consumption and CO2 production). Analyze ASAP. Quality control: daily calibration of blood gas analyzer, proficiency testing, two-point calibration, correlation with clinical status. Document: time drawn, FiO2, ventilator settings, patient temperature (temperature correction if needed — some institutions use corrected, others uncorrected values).",complications:"Sampling complications: hematoma, arterial spasm, thrombosis, nerve damage, infection, pseudoaneurysm. Result errors from pre-analytical problems leading to incorrect treatment decisions.",clinicalPearls:["Air bubbles raise PaO2 and lower PaCO2 — remove ALL bubbles immediately after sampling","Modified Allen test: hand should pink up within 5–10 seconds after releasing ulnar artery","Place sample on ICE if analysis will be delayed > 10 minutes — slows cellular metabolism","Document FiO2 and ventilator settings with every ABG — results are meaningless without this context"],examPitfalls:["Not performing modified Allen test before radial artery puncture","Not removing air bubbles from the sample — falsely raises PaO2","Using excess liquid heparin — dilutes the sample and lowers all values","Delaying analysis at room temperature — PaO2 falls and PaCO2 rises over time"],faqJson:[{question:"Why do air bubbles affect ABG results?",answer:"Air bubbles equilibrate with the blood sample. Room air PO2 (~150 mmHg) is typically higher than patient PaO2, so O2 diffuses FROM the bubble INTO the blood, falsely raising PaO2. Room air PCO2 (~0.3 mmHg) is much lower than patient PaCO2 (~40), so CO2 diffuses from blood into the bubble, falsely lowering PaCO2."},{question:"What is the modified Allen test?",answer:"It assesses collateral circulation (ulnar artery) before radial artery puncture. Steps: (1) have patient clench fist, (2) occlude both radial and ulnar arteries, (3) have patient open hand (blanched), (4) release ulnar artery only, (5) hand should pink up within 5–10 seconds. If positive: adequate collateral, safe to puncture radial. If negative: use alternate site."}],relatedLessonIds:[],relatedQuestionIds:[]}

];
